function AppointmentFormSheet({
  api,
  busy,
  calendar,
  calendars,
  closing,
  draft,
  mode,
  open,
  timezone,
  onChange,
  onClose,
  onSave,
}: {
  api: RistakApiClient;
  busy: boolean;
  calendar: CalendarItem | null;
  calendars: CalendarItem[];
  closing: boolean;
  draft: AppointmentDraft | null;
  mode: AppointmentFormMode;
  open: boolean;
  timezone: string;
  onChange: (draft: AppointmentDraft | null) => void;
  onClose: () => void;
  onSave: (draft: AppointmentDraft, scheduleMode: AppointmentScheduleMode) => void;
}) {
  const { height: viewportHeight } = useWindowDimensions();
  const [scheduleMode, setScheduleMode] = useState<AppointmentScheduleMode>('default');
  const [advancedPicker, setAdvancedPicker] = useState<AppointmentAdvancedPicker>(null);
  const [freeSlots, setFreeSlots] = useState<CalendarFreeSlot[]>([]);
  const [freeSlotsLoading, setFreeSlotsLoading] = useState(false);
  const [freeSlotsError, setFreeSlotsError] = useState('');
  const [selectedSlotDate, setSelectedSlotDate] = useState('');
  const [selectedSlot, setSelectedSlot] = useState<CalendarSlotSelection | null>(null);
  const [guestSearchQuery, setGuestSearchQuery] = useState('');
  const [guestContacts, setGuestContacts] = useState<ChatContact[]>([]);
  const [guestSearching, setGuestSearching] = useState(false);
  const [guestName, setGuestName] = useState('');
  const [guestContact, setGuestContact] = useState('');
  const [guestCreating, setGuestCreating] = useState(false);
  const [includeGuests, setIncludeGuests] = useState(false);
  const [calendarPickerOpen, setCalendarPickerOpen] = useState(false);
  const [assignmentUsers, setAssignmentUsers] = useState<CalendarUser[]>([]);
  const [assignmentLoading, setAssignmentLoading] = useState(false);
  const [assignmentError, setAssignmentError] = useState('');
  const freeSlotDateScrollRef = useRef<ScrollView | null>(null);
  const wheelScrollRefs = useRef<Record<string, ScrollView | null>>({});
  const wheelScrollValues = useRef<Record<string, Animated.Value>>({});
  const preferredSlotDateRef = useRef('');
  const freeSlotsGenerationRef = useRef(0);
  const freeSlotsAbortRef = useRef<AbortController | null>(null);
  const assignmentGenerationRef = useRef(0);
  const assignmentAbortRef = useRef<AbortController | null>(null);

  const activeDraftCalendar = useMemo(() => {
    const draftCalendarId = String(draft?.calendarId || '').trim();
    return calendars.find((item) => getCalendarKey(item) === draftCalendarId) || calendar || null;
  }, [calendar, calendars, draft?.calendarId]);
  const activeDraftCalendarKey = getCalendarKey(activeDraftCalendar);
  const activeDraftCalendarKeyRef = useRef(activeDraftCalendarKey);
  activeDraftCalendarKeyRef.current = activeDraftCalendarKey;
  const activeDraftCalendarIsRoundRobin = isRoundRobinCalendar(activeDraftCalendar);
  const assignmentTeamMemberIdsKey = (activeDraftCalendar?.teamMembers || [])
    .map(getCalendarTeamMemberId)
    .filter(Boolean)
    .join('\u0001');
  const assignmentRequestScope = [
    activeDraftCalendarKey,
    activeDraftCalendarIsRoundRobin ? 'round-robin' : 'standard',
    assignmentTeamMemberIdsKey,
  ].join('\u0002');
  const assignmentRequestScopeRef = useRef(assignmentRequestScope);
  assignmentRequestScopeRef.current = assignmentRequestScope;

  const updateDraft = useCallback((updates: Partial<AppointmentDraft>) => {
    if (!draft) return;
    onChange({ ...draft, ...updates });
  }, [draft, onChange]);

  const loadFreeSlots = useCallback(async () => {
    const calendarId = activeDraftCalendarKey;
    if (!calendarId) return;
    const generation = ++freeSlotsGenerationRef.current;
    freeSlotsAbortRef.current?.abort();
    const controller = new AbortController();
    freeSlotsAbortRef.current = controller;
    const isLatest = () => (
      freeSlotsGenerationRef.current === generation
      && !controller.signal.aborted
      && activeDraftCalendarKeyRef.current === calendarId
    );
    setFreeSlotsLoading(true);
    setFreeSlotsError('');
    try {
      const startDate = todayDateOnlyInBusinessTimezone(timezone);
      const endDate = addBusinessDateOnlyDays(startDate, 30);
      const response = await api.getFreeSlots(calendarId, startDate, endDate, timezone, {
        signal: controller.signal,
      });
      if (!isLatest()) return;
      const nextSlots = Array.isArray(response) ? response.filter((group) => Array.isArray(group.slots) && group.slots.length > 0) : [];
      const preferredDate = preferredSlotDateRef.current;
      setFreeSlots(nextSlots);
      setSelectedSlotDate((current) => {
        if (current && nextSlots.some((group) => group.date === current)) return current;
        if (preferredDate && nextSlots.some((group) => group.date === preferredDate)) return preferredDate;
        return nextSlots[0]?.date || '';
      });
    } catch (err) {
      if (isLatest() && !(err instanceof Error && err.name === 'AbortError')) {
        setFreeSlots([]);
        setFreeSlotsError(err instanceof Error ? err.message : 'No se pudieron cargar slots.');
      }
    } finally {
      if (freeSlotsAbortRef.current === controller) {
        freeSlotsAbortRef.current = null;
      }
      if (isLatest()) setFreeSlotsLoading(false);
    }
  }, [activeDraftCalendarKey, api, timezone]);

  const loadAssignmentUsers = useCallback(async () => {
    const calendarId = activeDraftCalendarKey;
    if (!calendarId) return;
    const scope = assignmentRequestScope;
    const teamMemberIds = assignmentTeamMemberIdsKey
      ? assignmentTeamMemberIdsKey.split('\u0001').filter(Boolean)
      : [];
    const generation = ++assignmentGenerationRef.current;
    assignmentAbortRef.current?.abort();
    const controller = new AbortController();
    assignmentAbortRef.current = controller;
    const isLatest = () => (
      assignmentGenerationRef.current === generation
      && !controller.signal.aborted
      && activeDraftCalendarKeyRef.current === calendarId
      && assignmentRequestScopeRef.current === scope
    );

    setAssignmentLoading(true);
    setAssignmentError('');
    try {
      const response = teamMemberIds.length > 0 && activeDraftCalendarIsRoundRobin
        ? await api.getCalendarUsersByIds(teamMemberIds, { signal: controller.signal })
        : await api.getCalendarUsers({ signal: controller.signal });
      if (!isLatest()) return;
      let users = unwrapCalendarUsers(response);
      if (!users.length && teamMemberIds.length) {
        users = teamMemberIds.map((id) => ({ id, name: `Usuario ${id.slice(0, 8)}...` }));
      }
      setAssignmentUsers(users);
    } catch (err) {
      if (isLatest() && !(err instanceof Error && err.name === 'AbortError')) {
        setAssignmentUsers(teamMemberIds.map((id) => ({ id, name: `Usuario ${id.slice(0, 8)}...` })));
        setAssignmentError(err instanceof Error ? err.message : 'No se pudo cargar el equipo.');
      }
    } finally {
      if (assignmentAbortRef.current === controller) {
        assignmentAbortRef.current = null;
      }
      if (isLatest()) setAssignmentLoading(false);
    }
  }, [
    activeDraftCalendarIsRoundRobin,
    activeDraftCalendarKey,
    api,
    assignmentRequestScope,
    assignmentTeamMemberIdsKey,
  ]);

  useEffect(() => {
    if (!open || !draft) return;
    preferredSlotDateRef.current = draft.dateOnly;
    setScheduleMode(mode === 'create' ? 'default' : 'custom');
    setAdvancedPicker(null);
    setSelectedSlot(null);
    setGuestSearchQuery('');
    setGuestContacts([]);
    setGuestSearching(false);
    setGuestName('');
    setGuestContact('');
    setIncludeGuests(Boolean(draft.guests.length));
    setCalendarPickerOpen(false);
  }, [draft?.contactId, draft?.eventId, mode, open]);

  useEffect(() => {
    if (!open || !draft) {
      setScheduleMode('default');
      setAdvancedPicker(null);
      setFreeSlots([]);
      setSelectedSlotDate('');
      setSelectedSlot(null);
      setGuestSearchQuery('');
      setGuestContacts([]);
      setGuestSearching(false);
      setGuestName('');
      setGuestContact('');
      setIncludeGuests(false);
      setCalendarPickerOpen(false);
      setAssignmentUsers([]);
      setAssignmentError('');
      return;
    }
  }, [Boolean(draft), open]);

  useEffect(() => {
    freeSlotsGenerationRef.current += 1;
    freeSlotsAbortRef.current?.abort();
    freeSlotsAbortRef.current = null;
    setFreeSlotsLoading(false);
    setFreeSlotsError('');
    setFreeSlots([]);
    setSelectedSlotDate('');
    setSelectedSlot(null);
  }, [activeDraftCalendarKey, open, scheduleMode]);

  useEffect(() => {
    if (!open || !draft || scheduleMode !== 'default') return;
    void loadFreeSlots();
  }, [Boolean(draft), loadFreeSlots, open, scheduleMode]);

  useEffect(() => {
    assignmentGenerationRef.current += 1;
    assignmentAbortRef.current?.abort();
    assignmentAbortRef.current = null;
    setAssignmentLoading(false);
    setAssignmentError('');
    setAssignmentUsers([]);
  }, [assignmentRequestScope, open]);

  useEffect(() => {
    if (!open || !draft || (!draft.assignedUserId && !activeDraftCalendarIsRoundRobin)) return;
    void loadAssignmentUsers();
  }, [activeDraftCalendarIsRoundRobin, Boolean(draft?.assignedUserId), loadAssignmentUsers, open]);

  useEffect(() => () => {
    freeSlotsGenerationRef.current += 1;
    freeSlotsAbortRef.current?.abort();
    freeSlotsAbortRef.current = null;
    assignmentGenerationRef.current += 1;
    assignmentAbortRef.current?.abort();
    assignmentAbortRef.current = null;
  }, []);

  useEffect(() => {
    if (!open || !draft || !selectedSlotDate || scheduleMode !== 'default') return;
    const index = freeSlots.findIndex((group) => group.date === selectedSlotDate);
    if (index <= 0) return;
    const scrollX = Math.max(0, index * FREE_SLOT_DATE_CHIP_SPAN - 22);
    requestAnimationFrame(() => {
      freeSlotDateScrollRef.current?.scrollTo({ x: scrollX, animated: true });
    });
  }, [draft, freeSlots, open, scheduleMode, selectedSlotDate]);

  useEffect(() => {
    const query = guestSearchQuery.trim();
    if (!open || !draft || query.length < 2) {
      setGuestContacts([]);
      setGuestSearching(false);
      return;
    }

    let cancelled = false;
    const timer = setTimeout(() => {
      setGuestSearching(true);
      api.searchContacts(query)
        .then((results) => {
          if (!cancelled) setGuestContacts(Array.isArray(results) ? results.slice(0, 6) : []);
        })
        .catch(() => {
          if (!cancelled) setGuestContacts([]);
        })
        .finally(() => {
          if (!cancelled) setGuestSearching(false);
        });
    }, 160);

    return () => {
      cancelled = true;
      clearTimeout(timer);
    };
  }, [api, Boolean(draft), guestSearchQuery, open]);

  const selectedDateParts = useMemo(() => {
    const fallbackDateOnly = todayDateOnlyInBusinessTimezone(timezone);
    const date = dateOnlyToCalendarDate(draft?.dateOnly || '') || dateOnlyToCalendarDate(fallbackDateOnly);
    return {
      year: date?.getFullYear() || Number(formatBusinessYear(fallbackDateOnly)) || 2026,
      month: (date?.getMonth() ?? 0) + 1,
      day: date?.getDate() || 1,
    };
  }, [draft?.dateOnly, timezone]);
  const selectedTimeMinutes = parseTimeToMinutes(draft?.startTime) ?? 9 * 60;
  const selectedTimeHour24 = Math.floor(selectedTimeMinutes / 60);
  const selectedTimeMinute = selectedTimeMinutes % 60;
  const selectedTimePeriod: 'AM' | 'PM' = selectedTimeHour24 >= 12 ? 'PM' : 'AM';
  const selectedTimeHour12 = selectedTimeHour24 % 12 || 12;
  const selectedDuration = Math.max(1, Math.min(TIMELINE_TOTAL_MINUTES, draft?.durationMinutes || 60));
  const selectedDurationHours = Math.max(0, Math.min(12, Math.floor(selectedDuration / 60)));
  const selectedDurationMinutes = Math.max(0, Math.min(59, selectedDuration % 60));
  const dateDayOptions = useMemo(
    () => Array.from({ length: getDaysInMonth(selectedDateParts.year, selectedDateParts.month) }, (_, index) => index + 1),
    [selectedDateParts.month, selectedDateParts.year],
  );
  const currentBusinessYear = Number(formatBusinessYear(todayDateOnlyInBusinessTimezone(timezone))) || selectedDateParts.year;
  const dateYearOptions = useMemo(() => {
    const startYear = Math.min(currentBusinessYear - 3, selectedDateParts.year - 3);
    const endYear = Math.max(currentBusinessYear + 9, selectedDateParts.year + 5);
    return Array.from({ length: endYear - startYear + 1 }, (_, index) => startYear + index);
  }, [currentBusinessYear, selectedDateParts.year]);
  const selectedSlotGroup = freeSlots.find((group) => group.date === selectedSlotDate) || null;
  const assignmentRequired = mode === 'create' && activeDraftCalendarIsRoundRobin;
  const showAssignmentPicker = Boolean(draft && (
    assignmentRequired ||
    draft.assignedUserId ||
    (activeDraftCalendarIsRoundRobin && (assignmentUsers.length || assignmentLoading || assignmentError))
  ));

  const setScheduleModeSafely = useCallback((nextMode: AppointmentScheduleMode) => {
    setScheduleMode(nextMode);
    setAdvancedPicker(null);
    if (nextMode !== 'default') setSelectedSlot(null);
  }, []);

  const saveDraftSafely = useCallback(() => {
    if (!draft) return;
    if (mode === 'create' && scheduleMode === 'default') {
      const selectionIsCurrent = isCurrentCalendarSlotSelection({
        calendarId: activeDraftCalendarKey,
        dateOnly: draft.dateOnly,
        freeSlots,
        selection: selectedSlot,
      });
      if (!selectionIsCurrent) {
        const hadSelection = Boolean(selectedSlot);
        setSelectedSlot(null);
        Alert.alert(
          hadSelection ? 'Horario desactualizado' : 'Elige un horario',
          hadSelection
            ? 'Ese horario ya no pertenece al calendario y fecha actuales. Selecciona otro horario antes de crear la cita.'
            : 'Selecciona uno de los horarios disponibles o cambia a Personalizado antes de crear la cita.',
        );
        return;
      }
    }
    onSave(draft, scheduleMode);
  }, [activeDraftCalendarKey, draft, freeSlots, mode, onSave, scheduleMode, selectedSlot]);

  const applyDatePart = useCallback((updates: Partial<typeof selectedDateParts>) => {
    const year = updates.year ?? selectedDateParts.year;
    const month = updates.month ?? selectedDateParts.month;
    const day = updates.day ?? selectedDateParts.day;
    updateDraft({ dateOnly: buildDateOnlyFromParts(year, month, day) });
  }, [selectedDateParts, updateDraft]);

  const applyTimePart = useCallback((updates: { hour?: number; minute?: number; period?: 'AM' | 'PM' }) => {
    const nextHour12 = updates.hour ?? selectedTimeHour12;
    const nextMinute = updates.minute ?? selectedTimeMinute;
    const nextPeriod = updates.period ?? selectedTimePeriod;
    const hour24 = nextPeriod === 'PM'
      ? (nextHour12 % 12) + 12
      : nextHour12 % 12;
    updateDraft({ startTime: formatMinutesAsTime(hour24 * 60 + nextMinute) });
  }, [selectedTimeHour12, selectedTimeMinute, selectedTimePeriod, updateDraft]);

  const applyDurationPart = useCallback((hours: number, minutes: number) => {
    const safeHours = Math.max(0, Math.min(12, Math.round(hours || 0)));
    const safeMinutes = Math.max(0, Math.min(59, Math.round(minutes || 0)));
    const total = Math.max(1, Math.min(TIMELINE_TOTAL_MINUTES, safeHours * 60 + safeMinutes));
    updateDraft({ durationMinutes: total });
  }, [updateDraft]);

  const addGuestToDraft = useCallback((guest: Omit<AppointmentGuest, 'id'> & { id?: string }) => {
    if (!draft) return;
    const name = guest.name.trim();
    const contactValue = guest.contact.trim();
    if (!name || !contactValue) {
      Alert.alert('Invitado incompleto', 'Agrega nombre y teléfono o correo para poder invitarlo.');
      return;
    }
    const normalizedContact = contactValue.toLowerCase();
    const exists = draft.guests.some((item) => item.contact.trim().toLowerCase() === normalizedContact);
    if (exists) return;
    updateDraft({
      guests: [
        ...draft.guests,
        {
          id: guest.id || createAppointmentGuestId(),
          name,
          contact: contactValue,
          contactId: guest.contactId,
        },
      ],
    });
  }, [draft, updateDraft]);

  const selectGuestContact = useCallback((contact: ChatContact) => {
    const delivery = getContactDelivery(contact);
    if (!delivery) {
      Alert.alert('Sin contacto', 'Este contacto no tiene teléfono ni correo registrado.');
      return;
    }
    addGuestToDraft({
      name: getContactName(contact),
      contact: delivery,
      contactId: contact.id,
    });
    setGuestSearchQuery('');
    setGuestContacts([]);
  }, [addGuestToDraft]);

  const createGuestContact = useCallback(async () => {
    const searchValue = guestSearchQuery.trim();
    const contactValue = (guestContact.trim() || (searchValue.includes('@') || /\d/.test(searchValue) ? searchValue : '')).trim();
    const nameValue = (guestName.trim() || (!contactValue && searchValue ? searchValue : '')).trim();
    if (!nameValue || !contactValue) {
      Alert.alert('Faltan datos', 'Escribe el nombre y el teléfono o correo del invitado.');
      return;
    }

    setGuestCreating(true);
    try {
      const isEmail = contactValue.includes('@');
      const created = await api.createContact({
        name: nameValue,
        full_name: nameValue,
        email: isEmail ? contactValue : undefined,
        phone: isEmail ? undefined : contactValue,
        source: 'mobile_native_appointment_guest',
      });
      addGuestToDraft({
        name: getContactName(created) || nameValue,
        contact: getContactDelivery(created) || contactValue,
        contactId: created.id,
      });
      setGuestSearchQuery('');
      setGuestContacts([]);
      setGuestName('');
      setGuestContact('');
    } catch (err) {
      Alert.alert('No se creó el contacto', err instanceof Error ? err.message : 'Intenta de nuevo.');
    } finally {
      setGuestCreating(false);
    }
  }, [addGuestToDraft, api, guestContact, guestName, guestSearchQuery]);

  const removeGuest = useCallback((guestId: string) => {
    if (!draft) return;
    updateDraft({ guests: draft.guests.filter((guest) => guest.id !== guestId) });
  }, [draft, updateDraft]);

  const appointmentWheelColumnHeight = Math.round(Math.min(390, Math.max(252, viewportHeight * 0.42)));
  const appointmentWheelScrollerHeight = Math.max(
    APPOINTMENT_WHEEL_OPTION_HEIGHT * 3,
    appointmentWheelColumnHeight - APPOINTMENT_WHEEL_LABEL_HEIGHT,
  );
  const appointmentWheelCenterPadding = Math.max(0, (appointmentWheelScrollerHeight - APPOINTMENT_WHEEL_OPTION_HEIGHT) / 2);

  type AppointmentWheelColumnOption<T extends string | number> = {
    key: string;
    label: string;
    value: T;
  };

  const getWheelColumnKey = (label: string) => `${advancedPicker || 'appointment'}-${label}`;

  const getWheelScrollValue = (columnKey: string, initialOffset: number) => {
    if (!wheelScrollValues.current[columnKey]) {
      wheelScrollValues.current[columnKey] = new Animated.Value(initialOffset);
    }
    return wheelScrollValues.current[columnKey];
  };

  const scrollWheelColumnToIndex = (columnKey: string, index: number, animated = true) => {
    const offsetY = Math.max(0, index) * APPOINTMENT_WHEEL_OPTION_HEIGHT;
    if (!animated) {
      getWheelScrollValue(columnKey, offsetY).setValue(offsetY);
    }
    wheelScrollRefs.current[columnKey]?.scrollTo({
      y: offsetY,
      animated,
    });
  };

  const renderWheelColumn = <T extends string | number,>(
    label: string,
    options: AppointmentWheelColumnOption<T>[],
    selectedValue: T,
    onSelect: (value: T) => void,
  ) => {
    const columnKey = getWheelColumnKey(label);
    const selectedIndex = Math.max(0, options.findIndex((option) => option.value === selectedValue));
    const scrollY = getWheelScrollValue(columnKey, selectedIndex * APPOINTMENT_WHEEL_OPTION_HEIGHT);
    const commitFromOffset = (event: NativeSyntheticEvent<NativeScrollEvent>, snapIfNeeded = false) => {
      if (!options.length) return;
      const offsetY = event.nativeEvent.contentOffset.y;
      const rawIndex = Math.round(offsetY / APPOINTMENT_WHEEL_OPTION_HEIGHT);
      const nextIndex = Math.max(0, Math.min(options.length - 1, rawIndex));
      const nextOption = options[nextIndex];
      if (!nextOption) return;
      const targetOffset = nextIndex * APPOINTMENT_WHEEL_OPTION_HEIGHT;
      if (snapIfNeeded && Math.abs(offsetY - targetOffset) > 1) {
        scrollWheelColumnToIndex(columnKey, nextIndex, false);
      }
      if (nextOption.value !== selectedValue) onSelect(nextOption.value);
    };

    return (
      <View style={[styles.appointmentWheelColumn, { height: appointmentWheelColumnHeight }]}>
        <View style={[styles.appointmentWheelColumnLabel, { height: APPOINTMENT_WHEEL_LABEL_HEIGHT }]}>
          <Text style={styles.appointmentWheelColumnLabelText}>{label}</Text>
        </View>
        <View style={[styles.appointmentWheelColumnScrollerFrame, { height: appointmentWheelScrollerHeight }]}>
          <View
            pointerEvents="none"
            style={[
              styles.appointmentWheelCenterHighlight,
              {
                top: appointmentWheelCenterPadding,
                height: APPOINTMENT_WHEEL_OPTION_HEIGHT,
              },
            ]}
          />
          <Animated.ScrollView
            ref={(ref) => { wheelScrollRefs.current[columnKey] = ref as unknown as ScrollView | null; }}
            alwaysBounceVertical={false}
            bounces={false}
            contentContainerStyle={[
              styles.appointmentWheelColumnContent,
              {
                paddingTop: appointmentWheelCenterPadding,
                paddingBottom: appointmentWheelCenterPadding,
              },
            ]}
            contentOffset={{ x: 0, y: selectedIndex * APPOINTMENT_WHEEL_OPTION_HEIGHT }}
            decelerationRate="fast"
            key={`${columnKey}-${options.length}`}
            onLayout={() => {
              requestAnimationFrame(() => scrollWheelColumnToIndex(columnKey, selectedIndex, false));
            }}
            onMomentumScrollEnd={(event) => commitFromOffset(event)}
            onScroll={Animated.event(
              [{ nativeEvent: { contentOffset: { y: scrollY } } }],
              { useNativeDriver: false },
            )}
            onScrollEndDrag={(event) => {
              const velocityY = event.nativeEvent.velocity?.y ?? 0;
              if (Math.abs(velocityY) < 0.05) commitFromOffset(event, true);
            }}
            overScrollMode="never"
            showsVerticalScrollIndicator={false}
            snapToAlignment="start"
            snapToInterval={APPOINTMENT_WHEEL_OPTION_HEIGHT}
            scrollEventThrottle={16}
            style={styles.appointmentWheelColumnScroller}
          >
            {options.map((option, index) => {
              const selected = index === selectedIndex;
              const distanceColor = scrollY.interpolate({
                inputRange: [
                  (index - 1) * APPOINTMENT_WHEEL_OPTION_HEIGHT,
                  index * APPOINTMENT_WHEEL_OPTION_HEIGHT,
                  (index + 1) * APPOINTMENT_WHEEL_OPTION_HEIGHT,
                ],
                outputRange: [COLORS.text, COLORS.accent, COLORS.text],
                extrapolate: 'clamp',
              });
              return (
                <Pressable
                  key={option.key}
                  accessibilityRole="button"
                  onPress={() => {
                    scrollWheelColumnToIndex(columnKey, index, true);
                    if (option.value !== selectedValue) onSelect(option.value);
                  }}
                  style={({ pressed }) => [
                    styles.appointmentWheelOption,
                    selected && styles.appointmentWheelOptionActive,
                    pressed && styles.pressed,
                  ]}
                >
                  <Animated.Text
                    style={[
                      styles.appointmentWheelOptionText,
                      selected && styles.appointmentWheelOptionTextActive,
                      { color: distanceColor },
                    ]}
                  >
                    {option.label}
                  </Animated.Text>
                </Pressable>
              );
            })}
          </Animated.ScrollView>
        </View>
      </View>
    );
  };

  const renderAdvancedPickerContent = () => {
    if (!advancedPicker) return null;

    if (advancedPicker === 'date') {
      return (
        <View style={styles.appointmentWheelSheetBody}>
          <View style={styles.appointmentWheelColumns}>
            {renderWheelColumn(
              'Día',
              dateDayOptions.map((day) => ({ key: `day-${day}`, label: String(day), value: day })),
              selectedDateParts.day,
              (day) => applyDatePart({ day }),
            )}
            {renderWheelColumn(
              'Mes',
              APPOINTMENT_DATE_MONTH_OPTIONS.map((month) => ({
                key: `month-${month.value}`,
                label: month.label.slice(0, 3),
                value: month.value,
              })),
              selectedDateParts.month,
              (month) => applyDatePart({ month }),
            )}
            {renderWheelColumn(
              'Año',
              dateYearOptions.map((year) => ({ key: `year-${year}`, label: String(year), value: year })),
              selectedDateParts.year,
              (year) => applyDatePart({ year }),
            )}
          </View>
          <PrimaryButton label="Listo" onPress={() => setAdvancedPicker(null)} />
        </View>
      );
    }

    if (advancedPicker === 'time') {
      return (
        <View style={styles.appointmentWheelSheetBody}>
          <View style={styles.appointmentWheelColumns}>
            {renderWheelColumn(
              'Hora',
              APPOINTMENT_TIME_HOUR_OPTIONS.map((hour) => ({ key: `hour-${hour}`, label: String(hour), value: hour })),
              selectedTimeHour12,
              (hour) => applyTimePart({ hour }),
            )}
            {renderWheelColumn(
              'Minutos',
              APPOINTMENT_TIME_MINUTE_OPTIONS.map((minute) => ({
                key: `minute-${minute}`,
                label: String(minute).padStart(2, '0'),
                value: minute,
              })),
              selectedTimeMinute,
              (minute) => applyTimePart({ minute }),
            )}
            {renderWheelColumn(
              'AM/PM',
              (['AM', 'PM'] as const).map((period) => ({ key: period, label: period, value: period })),
              selectedTimePeriod,
              (period) => applyTimePart({ period }),
            )}
          </View>
          <PrimaryButton label="Listo" onPress={() => setAdvancedPicker(null)} />
        </View>
      );
    }

    return (
      <View style={styles.appointmentWheelSheetBody}>
        <View style={styles.appointmentWheelColumns}>
          {renderWheelColumn(
            'Horas',
            APPOINTMENT_DURATION_HOUR_OPTIONS.map((hours) => ({
              key: `duration-hour-${hours}`,
              label: String(hours),
              value: hours,
            })),
            selectedDurationHours,
            (hours) => applyDurationPart(hours, selectedDurationMinutes),
          )}
          {renderWheelColumn(
            'Minutos',
            APPOINTMENT_DURATION_MINUTE_OPTIONS.map((minutes) => ({
              key: `duration-minute-${minutes}`,
              label: String(minutes).padStart(2, '0'),
              value: minutes,
            })),
            selectedDurationMinutes,
            (minutes) => applyDurationPart(selectedDurationHours, minutes),
          )}
        </View>
        <PrimaryButton label="Listo" onPress={() => setAdvancedPicker(null)} />
      </View>
    );
  };

  const renderAdvancedPickerSheet = () => {
    if (!advancedPicker) return null;
    const title = advancedPicker === 'date' ? 'Fecha' : advancedPicker === 'time' ? 'Hora' : 'Duración';

    return (
      <BottomActionSheet open title={title} onClose={() => setAdvancedPicker(null)}>
        {renderAdvancedPickerContent()}
      </BottomActionSheet>
    );
  };

  const renderGuestsSection = () => (
    <View style={styles.appointmentGuestSection}>
      <View style={styles.appointmentGuestHeader}>
        <Text style={styles.appointmentSectionTitle}>Invitados</Text>
        <View style={styles.appointmentGuestToggle}>
          {[
            { value: true, label: 'Sí' },
            { value: false, label: 'No' },
          ].map((option) => {
            const selected = includeGuests === option.value;
            return (
              <Pressable
                key={option.label}
                accessibilityRole="button"
                onPress={() => {
                  setIncludeGuests(option.value);
                  if (!option.value) updateDraft({ guests: [] });
                }}
                style={({ pressed }) => [
                  styles.appointmentGuestToggleButton,
                  selected && styles.appointmentGuestToggleButtonActive,
                  pressed && styles.pressed,
                ]}
              >
                <LiquidControlBackground selected={selected} />
                <Text style={[styles.appointmentGuestToggleText, selected && styles.appointmentGuestToggleTextActive]}>
                  {option.label}
                </Text>
              </Pressable>
            );
          })}
        </View>
        {draft?.guests.length ? <Text style={styles.appointmentGuestCount}>{draft.guests.length}</Text> : null}
      </View>
      {!includeGuests ? null : (
        <>
          <Text style={styles.appointmentHint}>Busca un contacto guardado o agrega uno nuevo para esta cita.</Text>
          <View style={styles.sheetSearchBox}>
            <Search size={18} color={COLORS.muted} strokeWidth={2.4} />
            <TextInput
              value={guestSearchQuery}
              onChangeText={setGuestSearchQuery}
              placeholder="Buscar en contactos..."
              placeholderTextColor={COLORS.muted}
              autoCapitalize="words"
              autoCorrect={false}
              style={styles.sheetSearchInput}
            />
          </View>
          {guestSearching ? (
            <View style={styles.appointmentInlineLoading}>
              <ActivityIndicator color={COLORS.accent} />
              <Text style={styles.caption}>Buscando contactos...</Text>
            </View>
          ) : guestContacts.length ? (
            <View style={styles.appointmentGuestResults}>
              {guestContacts.map((contact) => (
                <ContactPickerRow
                  key={contact.id}
                  contact={contact}
                  showSendIcon={false}
                  onPress={() => selectGuestContact(contact)}
                />
              ))}
            </View>
          ) : guestSearchQuery.trim().length >= 2 ? (
            <Text style={styles.appointmentHint}>No aparece en contactos. Créalo aquí mismo.</Text>
          ) : null}
          <View style={styles.appointmentGuestManual}>
            <AppointmentTextField
              compact
              label="Nombre completo"
              value={guestName}
              placeholder="Ej. Ana López"
              onChangeText={setGuestName}
            />
            <AppointmentTextField
              compact
              label="Num Whats o correo"
              value={guestContact}
              placeholder="Ej. +52 656 000 0000 o correo"
              onChangeText={setGuestContact}
            />
          </View>
          <Pressable
            accessibilityRole="button"
            disabled={guestCreating}
            onPress={createGuestContact}
            style={({ pressed }) => [
              styles.appointmentGuestAddButton,
              guestCreating && styles.disabledButton,
              pressed && styles.pressed,
            ]}
          >
            <LiquidControlBackground />
            {guestCreating ? <ActivityIndicator color={COLORS.text} /> : <Plus size={18} color={COLORS.text} strokeWidth={2.6} />}
            <Text style={styles.appointmentGuestAddText}>Agregar invitado</Text>
          </Pressable>
        </>
      )}
      {includeGuests && !draft?.guests.length ? (
        <Text style={styles.appointmentHint}>Todavía no agregas invitados.</Text>
      ) : null}
      {draft?.guests.length ? (
        <View style={styles.appointmentGuestList}>
          {draft.guests.map((guest) => (
            <View key={guest.id} style={styles.appointmentGuestItem}>
              <View style={styles.appointmentGuestAvatar}>
                <Text style={styles.avatarText}>{guest.name.slice(0, 1).toUpperCase()}</Text>
              </View>
              <View style={styles.appointmentGuestCopy}>
                <Text numberOfLines={1} style={styles.appointmentGuestName}>{guest.name}</Text>
                <Text numberOfLines={1} style={styles.appointmentGuestContact}>{guest.contact}</Text>
              </View>
              <Pressable
                accessibilityRole="button"
                onPress={() => removeGuest(guest.id)}
                style={({ pressed }) => [styles.appointmentGuestRemove, pressed && styles.pressed]}
              >
                <LiquidControlBackground />
                <X size={16} color={COLORS.muted} strokeWidth={2.6} />
              </Pressable>
            </View>
          ))}
        </View>
      ) : null}
    </View>
  );

  const headerContactName = draft?.contact ? getContactName(draft.contact) : '';
  const advancedPickerTitle = advancedPicker === 'date'
    ? 'Elige la fecha'
    : advancedPicker === 'time'
      ? 'Elige la hora'
      : advancedPicker === 'duration'
        ? 'Duración'
        : '';
  const activeCalendarId = getCalendarKey(activeDraftCalendar);
  const selectDraftCalendar = useCallback((nextCalendar: CalendarItem) => {
    // Invalidate in-flight work synchronously. Waiting for the next effect
    // leaves a small microtask window where the previous calendar can still
    // paint its slots/team after the user has already selected the new one.
    freeSlotsGenerationRef.current += 1;
    freeSlotsAbortRef.current?.abort();
    freeSlotsAbortRef.current = null;
    assignmentGenerationRef.current += 1;
    assignmentAbortRef.current?.abort();
    assignmentAbortRef.current = null;
    updateDraft({ calendarId: getCalendarKey(nextCalendar), assignedUserId: '' });
    setFreeSlotsLoading(false);
    setFreeSlotsError('');
    setFreeSlots([]);
    setSelectedSlot(null);
    setSelectedSlotDate('');
    setAssignmentLoading(false);
    setAssignmentError('');
    setAssignmentUsers([]);
    setCalendarPickerOpen(false);
  }, [updateDraft]);
  const sheetTitle = calendarPickerOpen
    ? 'Calendarios'
    : advancedPickerTitle || (mode === 'edit' ? 'Editar cita' : 'Agendar una cita');
  const sheetSubtitle = calendarPickerOpen || advancedPickerTitle
    ? undefined
    : headerContactName || (activeDraftCalendar ? getCalendarTitle(activeDraftCalendar) : 'Mi calendario');
  const closeActiveSheetPanel = calendarPickerOpen
    ? () => setCalendarPickerOpen(false)
    : advancedPickerTitle
      ? () => setAdvancedPicker(null)
      : onClose;

  return (
    <>
    <BottomActionSheet
      closing={closing}
      open={open}
      title={sheetTitle}
      subtitle={sheetSubtitle}
      onClose={closeActiveSheetPanel}
    >
      {!draft ? (
        <View style={styles.sheetInlineState}>
          <Text style={styles.caption}>No hay cita para editar.</Text>
        </View>
      ) : calendarPickerOpen ? (
        <AppointmentCalendarPickerList
          calendars={calendars}
          selectedCalendarId={activeCalendarId}
          onSelect={selectDraftCalendar}
        />
      ) : advancedPicker ? (
        renderAdvancedPickerContent()
      ) : (
        <KeyboardAvoidingView>
          <ScrollView
            contentContainerStyle={styles.appointmentFormBody}
            keyboardShouldPersistTaps="handled"
            showsVerticalScrollIndicator={false}
          >
            <AppointmentSelectField
              label="Calendario"
              value={activeDraftCalendar ? getCalendarTitle(activeDraftCalendar) : 'Mi calendario'}
              icon={CalendarDays}
              onPress={() => {
                setAdvancedPicker(null);
                setCalendarPickerOpen(true);
              }}
            />

            <View style={styles.appointmentSection}>
              <Text style={styles.appointmentFieldLabel}>Estado</Text>
              <View style={styles.appointmentChipRow}>
                {APPOINTMENT_STATUS_OPTIONS.map((option) => {
                  const selected = normalizeAppointmentStatus(draft.appointmentStatus) === option.value;
                  return (
                    <Pressable
                      key={option.value}
                      accessibilityRole="button"
                      onPress={() => updateDraft({ appointmentStatus: option.value })}
                      style={({ pressed }) => [
                        styles.appointmentChoiceChip,
                        selected && styles.appointmentChoiceChipActive,
                        pressed && styles.pressed,
                      ]}
                    >
                      <LiquidControlBackground selected={selected} />
                      <Text style={[styles.appointmentChoiceText, selected && styles.appointmentChoiceTextActive]}>
                        {option.label}
                      </Text>
                    </Pressable>
                  );
                })}
              </View>
            </View>

            {showAssignmentPicker ? (
              <View style={styles.appointmentSection}>
                <Text style={styles.appointmentFieldLabel}>
                  {assignmentRequired ? 'Elegir miembro del equipo' : 'Persona asignada'}
                </Text>
                {assignmentLoading ? (
                  <View style={styles.sheetInlineState}>
                    <ActivityIndicator color={COLORS.accent} />
                    <Text style={styles.caption}>Cargando equipo...</Text>
                  </View>
                ) : assignmentUsers.length ? (
                  <View style={styles.appointmentChipRow}>
                    {!assignmentRequired ? (
                      <Pressable
                        accessibilityRole="button"
                        onPress={() => updateDraft({ assignedUserId: '' })}
                        style={({ pressed }) => [
                          styles.appointmentChoiceChip,
                          !draft.assignedUserId && styles.appointmentChoiceChipActive,
                          pressed && styles.pressed,
                        ]}
                      >
                        <LiquidControlBackground selected={!draft.assignedUserId} />
                        <Text style={[styles.appointmentChoiceText, !draft.assignedUserId && styles.appointmentChoiceTextActive]}>
                          Sin asignar
                        </Text>
                      </Pressable>
                    ) : null}
                    {assignmentUsers.map((user) => {
                      const id = getCalendarUserId(user);
                      const selected = draft.assignedUserId === id;
                      return (
                        <Pressable
                          key={id}
                          accessibilityRole="button"
                          onPress={() => updateDraft({ assignedUserId: id })}
                          style={({ pressed }) => [
                          styles.appointmentChoiceChip,
                          selected && styles.appointmentChoiceChipActive,
                          pressed && styles.pressed,
                        ]}
                      >
                          <LiquidControlBackground selected={selected} />
                          <Text numberOfLines={1} style={[styles.appointmentChoiceText, selected && styles.appointmentChoiceTextActive]}>
                            {getCalendarUserLabel(user)}
                          </Text>
                          <Text numberOfLines={1} style={[styles.appointmentChoiceSubtext, selected && styles.appointmentChoiceTextActive]}>
                            {getCalendarUserDetail(user)}
                          </Text>
                        </Pressable>
                      );
                    })}
                  </View>
                ) : (
                  <Text style={styles.appointmentHint}>
                    {assignmentError || (assignmentRequired ? 'No pudimos cargar el equipo. Reintenta antes de guardar.' : 'No hay equipo para asignar.')}
                  </Text>
                )}
              </View>
            ) : null}

            <View style={styles.appointmentSection}>
              <AppointmentFieldLabel label="Fecha y hora" required />
              <View style={styles.appointmentSegmentedTabs}>
                {[
                  { value: 'default' as const, label: 'Por defecto' },
                  { value: 'custom' as const, label: 'Personalizado' },
                ].map((option) => {
                  const selected = scheduleMode === option.value;
                  return (
                    <Pressable
                      key={option.value}
                      accessibilityRole="button"
                      onPress={() => setScheduleModeSafely(option.value)}
                      style={({ pressed }) => [
                        styles.appointmentSegmentedTab,
                        selected && styles.appointmentSegmentedTabActive,
                        pressed && styles.pressed,
                      ]}
                    >
                      <LiquidControlBackground selected={selected} />
                      <Text style={[styles.appointmentChoiceText, selected && styles.appointmentChoiceTextActive]}>
                        {option.label}
                      </Text>
                    </Pressable>
                  );
                })}
              </View>
              {scheduleMode === 'default' ? (
                <View style={styles.freeSlotPanel}>
                  {freeSlotsLoading ? (
                    <View style={styles.sheetInlineState}>
                      <ActivityIndicator color={COLORS.accent} />
                      <Text style={styles.caption}>Buscando horarios...</Text>
                    </View>
                  ) : freeSlotsError ? (
                    <View style={styles.sheetInlineState}>
                      <Text style={styles.calendarErrorText}>{freeSlotsError}</Text>
                      <SecondaryButton label="Reintentar" onPress={loadFreeSlots} />
                    </View>
                  ) : freeSlots.length ? (
                    <View style={styles.freeSlotStack}>
                      <Text style={styles.appointmentHint}>Elige una fecha disponible</Text>
                      <ScrollView
                        ref={freeSlotDateScrollRef}
                        horizontal
                        showsHorizontalScrollIndicator={false}
                        contentContainerStyle={styles.freeSlotDateRow}
                      >
                        {freeSlots.map((group) => {
                          const groupDate = group.date || '';
                          const groupSlots = group.slots || [];
                          const selected = selectedSlotDate === groupDate;
                          return (
                            <Pressable
                              key={groupDate}
                              accessibilityRole="button"
                              onPress={() => {
                                setSelectedSlotDate(groupDate);
                                setSelectedSlot(null);
                              }}
                              style={({ pressed }) => [
                              styles.freeSlotDateChip,
                              selected && styles.freeSlotDateChipActive,
                              pressed && styles.pressed,
                            ]}
                          >
                              <LiquidControlBackground selected={selected} />
                              <Text numberOfLines={1} style={[styles.freeSlotDate, selected && styles.freeSlotDateActive]}>
                                {formatBusinessDayHeader(groupDate)}
                              </Text>
                              <Text numberOfLines={1} style={[styles.freeSlotCount, selected && styles.freeSlotDateActive]}>
                                {groupSlots.length} horario{groupSlots.length === 1 ? '' : 's'}
                              </Text>
                            </Pressable>
                          );
                        })}
                      </ScrollView>
                      <Text style={styles.appointmentHint}>Horario</Text>
                      <View style={styles.freeSlotTimeGrid}>
                        {(selectedSlotGroup?.slots || []).slice(0, 18).map((slot) => {
                          const fields = isoToBusinessDateTimeFields(slot, timezone);
                          const selected = selectedSlot?.slot === slot;
                          const durationMinutes = getCalendarSlotDurationMinutes(activeDraftCalendar);
                          const slotDateOnly = fields.dateOnly || selectedSlotDate || draft.dateOnly;
                          const slotStartTime = fields.time || draft.startTime;
                          const slotEndFields = addMinutesToBusinessDateTime(slotDateOnly, slotStartTime, durationMinutes);
                          return (
                            <Pressable
                              key={slot}
                              accessibilityRole="button"
                              onPress={() => {
                                setSelectedSlot({
                                  calendarId: activeDraftCalendarKey,
                                  groupDate: selectedSlotDate,
                                  dateOnly: slotDateOnly,
                                  slot,
                                });
                                updateDraft({
                                  dateOnly: slotDateOnly,
                                  startTime: slotStartTime,
                                  durationMinutes,
                                });
                              }}
                              style={({ pressed }) => [
                                styles.freeSlotChip,
                                selected && styles.freeSlotChipActive,
                                pressed && styles.pressed,
                              ]}
                            >
                              <LiquidControlBackground selected={selected} />
                              <Text numberOfLines={1} style={[styles.freeSlotTime, selected && styles.freeSlotTimeActive]}>
                                {formatCalendarEventTime(slot, timezone)}
                              </Text>
                              <Text numberOfLines={1} style={[styles.freeSlotDate, selected && styles.freeSlotDateActive]}>
                                {slotEndFields.time}
                              </Text>
                            </Pressable>
                          );
                        })}
                      </View>
                    </View>
                  ) : (
                    <Text style={styles.appointmentHint}>No hay horarios disponibles en los próximos 30 días.</Text>
                  )}
                </View>
              ) : null}
            </View>

            {scheduleMode === 'custom' ? (
              <View style={styles.appointmentSection}>
                <View style={styles.appointmentFieldGrid}>
                  <AppointmentSelectField
                    compact
                    label="Fecha"
                    value={formatAppointmentDateField(draft.dateOnly)}
                    onPress={() => setAdvancedPicker((current) => (current === 'date' ? null : 'date'))}
                  />
                  <AppointmentSelectField
                    compact
                    label="Hora"
                    value={formatAppointmentTimeField(draft.startTime)}
                    onPress={() => setAdvancedPicker((current) => (current === 'time' ? null : 'time'))}
                  />
                </View>
                <AppointmentSelectField
                  label="Duración"
                  value={formatAppointmentDurationLabel(draft.durationMinutes)}
                  onPress={() => setAdvancedPicker((current) => (current === 'duration' ? null : 'duration'))}
                />
              </View>
            ) : null}

            {renderGuestsSection()}

            <AppointmentTextField
              multiline
              label="Notas"
              value={draft.notes}
              placeholder="Añade instrucciones, acuerdos o detalles importantes..."
              onChangeText={(value) => updateDraft({ notes: value })}
            />

            <PrimaryButton
              label={mode === 'edit' ? 'Guardar cambios' : 'Crear cita'}
              busy={busy}
              onPress={saveDraftSafely}
            />
          </ScrollView>
        </KeyboardAvoidingView>
      )}
    </BottomActionSheet>
    </>
  );
}

