function NativeAgentHubSheet({
  api,
  open,
  onClose,
}: {
  api: RistakApiClient;
  open: boolean;
  onClose: () => void;
}) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [notice, setNotice] = useState('');
  const [aiStatus, setAiStatus] = useState<AIAgentConfigStatus | null>(null);
  const [agents, setAgents] = useState<ConversationalAgentDefinition[]>([]);
  const [busyAgentIds, setBusyAgentIds] = useState<string[]>([]);
  const [editingAgent, setEditingAgent] = useState<ConversationalAgentDefinition | null>(null);
  const [draft, setDraft] = useState<AgentEditorDraft | null>(null);
  const [savingEditor, setSavingEditor] = useState(false);

  const load = useCallback(async (silent = false) => {
    if (!silent) setLoading(true);
    setError('');
    try {
      const nextAiStatus = await api.getAIAgentConfig();
      setAiStatus(nextAiStatus);
      if (!nextAiStatus?.configured || nextAiStatus?.needsReconnect) {
        setAgents([]);
        return;
      }
      const nextAgents = await api.getConversationalAgents();
      setAgents((Array.isArray(nextAgents) ? nextAgents : []).slice().sort((a, b) => Number(a.position || 0) - Number(b.position || 0)));
    } catch (err) {
      const message = err instanceof Error ? err.message : 'No se pudo cargar el agente conversacional.';
      if (silent) setNotice('No se pudo actualizar el Hub. Se conserva la última información cargada.');
      else setError(message);
    } finally {
      if (!silent) setLoading(false);
    }
  }, [api]);

  useEffect(() => {
    if (!open) return;
    setNotice('');
    void load(Boolean(agents.length));
  }, [open]);

  const patchBusy = (agentId: string, busy: boolean) => {
    setBusyAgentIds((current) => busy
      ? Array.from(new Set([...current, agentId]))
      : current.filter((id) => id !== agentId));
  };

  const toggleAgent = async (agent: ConversationalAgentDefinition) => {
    if (busyAgentIds.includes(agent.id)) return;
    const nextEnabled = !agent.enabled;
    const previousAgent = agent;
    patchBusy(agent.id, true);
    setNotice('');
    setAgents((current) => current.map((item) => item.id === agent.id ? { ...item, enabled: nextEnabled } : item));
    try {
      const updated = await api.updateConversationalAgent(agent.id, { enabled: nextEnabled });
      setAgents((current) => current.map((item) => item.id === agent.id ? { ...item, ...updated } : item));
    } catch (err) {
      setAgents((current) => current.map((item) => item.id === agent.id ? previousAgent : item));
      Alert.alert('Agente conversacional', err instanceof Error ? err.message : 'No se pudo cambiar el estado del agente.');
    } finally {
      patchBusy(agent.id, false);
    }
  };

  const resetSkipped = async (agent: ConversationalAgentDefinition) => {
    if (busyAgentIds.includes(agent.id)) return;
    patchBusy(agent.id, true);
    setNotice('');
    try {
      await api.resetConversationalAgentSkippedContacts(agent.id);
      setNotice(`${agent.name || 'El agente'} puede volver a tomar los chats que había omitido.`);
    } catch (err) {
      Alert.alert('Agente conversacional', err instanceof Error ? err.message : 'No se pudieron reiniciar las omisiones.');
    } finally {
      patchBusy(agent.id, false);
    }
  };

  const editAgent = (agent: ConversationalAgentDefinition) => {
    setEditingAgent(agent);
    setDraft(createAgentEditorDraft(agent));
    setNotice('');
  };

  const saveAgent = async () => {
    if (!editingAgent || !draft || savingEditor) return;
    const name = draft.name.trim();
    if (!name) {
      Alert.alert('Falta el nombre', 'Ponle un nombre al agente antes de guardar.');
      return;
    }
    setSavingEditor(true);
    try {
      const updated = await api.updateConversationalAgent(editingAgent.id, {
        name,
        aiProvider: draft.aiProvider,
        model: draft.model,
        promptConfig: {
          schemaVersion: 1,
          templateVersion: editingAgent.promptConfig?.templateVersion || 'ristak-conversational-v1',
          editableText: draft.promptText,
        },
        contactScope: draft.contactScope,
        hideAttendedNotifications: draft.hideAttendedNotifications,
      });
      setAgents((current) => current.map((agent) => agent.id === updated.id ? { ...agent, ...updated } : agent));
      setEditingAgent(null);
      setDraft(null);
      setNotice('Cambios guardados.');
    } catch (err) {
      Alert.alert('No se pudo guardar', err instanceof Error ? err.message : 'Intenta otra vez.');
    } finally {
      setSavingEditor(false);
    }
  };

  const close = () => {
    if (editingAgent) {
      setEditingAgent(null);
      setDraft(null);
      return;
    }
    onClose();
  };

  const aiReady = Boolean(aiStatus?.configured && !aiStatus?.needsReconnect);
  const enabledCapabilities = editingAgent ? getEnabledAgentCapabilities(editingAgent) : [];

  return (
    <BottomActionSheet
      open={open}
      title={editingAgent ? 'Editar agente' : 'Agente conversacional'}
      subtitle={editingAgent ? (editingAgent.name || 'Agente') : 'Control y configuración'}
      onClose={close}
    >
      {editingAgent && draft ? (
        <ScrollView contentContainerStyle={styles.agentEditorContent} keyboardShouldPersistTaps="handled" showsVerticalScrollIndicator={false}>
          <Pressable accessibilityRole="button" onPress={close} style={({ pressed }) => [styles.agentEditorBack, pressed && styles.pressed]}>
            <ChevronLeft size={20} color={COLORS.text} strokeWidth={2.4} />
            <Text style={styles.agentEditorBackText}>Volver a agentes</Text>
          </Pressable>
          <View style={styles.agentEditorSection}>
            <View style={styles.agentEditorDirectHeader}>
              <View style={styles.agentEditorDirectIcon}><Bot size={18} color={COLORS.white} strokeWidth={2.4} /></View>
              <View style={styles.agentEditorDirectCopy}>
                <Text style={styles.agentEditorDirectTitle}>Flujo directo</Text>
                <Text style={styles.agentEditorDirectText}>Una sola IA conversa y usa herramientas nativas.</Text>
              </View>
            </View>
            <Text style={styles.agentEditorSectionTitle}>1. Instrucciones de tu agente</Text>
            <AgentEditorTextField label="Nombre del agente" value={draft.name} placeholder="Nombre del agente" onChange={(name) => setDraft((current) => current ? { ...current, name } : current)} />
            <View style={styles.agentEditorFieldGroup}>
              <Text style={styles.agentEditorFieldLabel}>Tono, guion y conocimiento del negocio</Text>
              <TextInput
                value={draft.promptText}
                onChangeText={(promptText) => setDraft((current) => current ? { ...current, promptText } : current)}
                multiline
                textAlignVertical="top"
                placeholder="Escribe aquí cómo debe atender, qué debe saber y cómo quieres que hable."
                placeholderTextColor={COLORS.muted}
                style={[styles.agentEditorInput, styles.agentEditorPromptTextarea]}
              />
              <Text style={styles.agentEditorHelp}>Puedes dejar la plantilla, editarla o borrarla completa. Las herramientas y validaciones siguen protegidas por Ristak.</Text>
            </View>
          </View>
          <View style={styles.agentEditorSection}>
            <Text style={styles.agentEditorSectionTitle}>2. Capacidades protegidas</Text>
            <Text style={styles.agentEditorHelp}>Estas son las herramientas nativas que el agente realmente puede ejecutar. Aquí se muestran con candado para no romper su configuración.</Text>
            {enabledCapabilities.length ? (
              <View style={styles.agentCapabilityList}>
                {enabledCapabilities.map((capability) => (
                  <View key={capability.id} style={styles.agentCapabilityRow}>
                    <View style={[styles.agentCapabilityIcon, !capability.ready && styles.agentCapabilityIconWarning]}>
                      {capability.ready
                        ? <CheckCircle2 size={18} color={COLORS.success} strokeWidth={2.45} />
                        : <CircleAlert size={18} color={COLORS.danger} strokeWidth={2.45} />}
                    </View>
                    <View style={styles.agentCapabilityCopy}>
                      <Text style={styles.agentCapabilityTitle}>{capability.label}</Text>
                      <Text style={styles.agentCapabilityText}>{capability.ready
                        ? capability.summary
                        : capability.missingConfiguration.join(' ') || 'Esta capacidad necesita configuración.'}</Text>
                    </View>
                    <Text style={styles.agentCapabilityLock}>Blindada</Text>
                  </View>
                ))}
              </View>
            ) : (
              <Text style={styles.agentEditorHelp}>Este agente todavía no tiene capacidades activas.</Text>
            )}
            <Text style={styles.agentEditorHelp}>Para agregar, quitar o configurar calendarios, cobros, enlaces y entregas al equipo, usa el constructor completo en Ristak para escritorio.</Text>
          </View>
          <View style={styles.agentEditorSection}>
            <Text style={styles.agentEditorSectionTitle}>3. Operación</Text>
            <AgentOptionGroup label="¿Qué IA va a contestar?" options={AGENT_PROVIDER_OPTIONS} selected={draft.aiProvider} onChange={(aiProvider) => setDraft((current) => current ? { ...current, aiProvider, model: AGENT_PROVIDER_DEFAULT_MODEL[aiProvider] } : current)} />
            <AgentOptionGroup
              label="Modelo"
              options={(AGENT_MODEL_OPTIONS[draft.aiProvider] || []).some((option) => option.id === draft.model)
                ? (AGENT_MODEL_OPTIONS[draft.aiProvider] || [])
                : [{ id: draft.model, label: draft.model }, ...(AGENT_MODEL_OPTIONS[draft.aiProvider] || [])]}
              selected={draft.model}
              onChange={(model) => setDraft((current) => current ? { ...current, model } : current)}
            />
            <SettingsToggleRow embedded title="Ocultar notificaciones mientras atiende" description="Evita alertas normales mientras la IA lleva la conversación." checked={draft.hideAttendedNotifications} onChange={(hideAttendedNotifications) => setDraft((current) => current ? { ...current, hideAttendedNotifications } : current)} />
            <AgentOptionGroup label="¿A quién puede atender?" options={AGENT_SCOPE_OPTIONS} selected={draft.contactScope} onChange={(contactScope) => setDraft((current) => current ? { ...current, contactScope } : current)} />
            <Text style={styles.agentEditorHelp}>Las condiciones avanzadas de entrada y salida se conservan intactas y se administran desde el panel completo.</Text>
          </View>
          <PrimaryButton label="Guardar cambios" busy={savingEditor} busyLabel="Guardando..." onPress={() => void saveAgent()} />
        </ScrollView>
      ) : loading && !agents.length ? (
        <View style={styles.agentHubState}>
          <ActivityIndicator color={COLORS.accent} />
        </View>
      ) : !aiReady ? (
        <View style={styles.agentHubState}>
          <View style={styles.agentHubStateIcon}><Bot size={24} color={COLORS.muted} strokeWidth={2.2} /></View>
          <Text style={styles.agentHubStateTitle}>{aiStatus?.needsReconnect ? 'Reconecta OpenAI' : 'Conecta OpenAI'}</Text>
          <Text style={styles.agentHubStateText}>Hazlo en Ajustes → Asistente Personal AI para usar el agente conversacional.</Text>
        </View>
      ) : error ? (
        <View style={styles.agentHubState}>
          <Text style={styles.errorText}>{error}</Text>
          <SecondaryButton label="Reintentar" onPress={() => void load()} />
        </View>
      ) : (
        <ScrollView contentContainerStyle={styles.agentHubContent} showsVerticalScrollIndicator={false}>
          {notice ? <Text style={styles.agentHubNotice}>{notice}</Text> : null}
          {agents.length ? agents.map((agent) => {
            const busy = busyAgentIds.includes(agent.id);
            return (
              <View key={agent.id} style={styles.agentHubRow}>
                <View style={[styles.agentHubRobot, agent.enabled && styles.agentHubRobotActive]}>
                  <Bot size={21} color={agent.enabled ? COLORS.white : COLORS.muted} strokeWidth={2.25} />
                </View>
                <View style={styles.agentHubRowCopy}>
                  <Text numberOfLines={1} style={styles.agentHubRowTitle}>{agent.name || 'Agente'}</Text>
                  <Text style={[styles.agentHubRowStatus, agent.enabled && styles.agentHubRowStatusActive]}>{agent.enabled ? 'Activo' : 'Pausado'}</Text>
                  <Text numberOfLines={1} style={styles.agentHubRowMeta}>{agent.aiProvider || 'OpenAI'} · {agent.model || 'Modelo automático'}</Text>
                </View>
                {busy ? <ActivityIndicator color={COLORS.accent} size="small" /> : (
                  <Switch
                    accessibilityLabel={`Activar ${agent.name || 'agente'}`}
                    value={Boolean(agent.enabled)}
                    onValueChange={() => void toggleAgent(agent)}
                    thumbColor={COLORS.white}
                    trackColor={{ false: COLORS.panelSoft, true: COLORS.accent }}
                  />
                )}
                <View style={styles.agentHubRowActions}>
                  <Pressable accessibilityRole="button" accessibilityLabel={`Editar ${agent.name || 'agente'}`} onPress={() => editAgent(agent)} style={({ pressed }) => [styles.agentHubIconButton, pressed && styles.pressed]}>
                    <Pencil size={17} color={COLORS.text} strokeWidth={2.25} />
                  </Pressable>
                  <Pressable accessibilityRole="button" accessibilityLabel={`Reiniciar omisiones de ${agent.name || 'agente'}`} disabled={busy} onPress={() => void resetSkipped(agent)} style={({ pressed }) => [styles.agentHubIconButton, busy && styles.disabledButton, pressed && styles.pressed]}>
                    <Repeat2 size={17} color={COLORS.muted} strokeWidth={2.25} />
                  </Pressable>
                </View>
              </View>
            );
          }) : (
            <View style={styles.agentHubState}>
              <Text style={styles.agentHubStateTitle}>Aún no hay agentes</Text>
              <Text style={styles.agentHubStateText}>Créalo desde el panel de escritorio; aquí podrás encenderlo, pausarlo y configurarlo.</Text>
            </View>
          )}
        </ScrollView>
      )}
    </BottomActionSheet>
  );
}

function ConversationAgentActionRows({
  agentBusyAction,
  agentLoading,
  agentStates = [],
  contact,
  onAgentAction,
  sectionLabel = 'Agente conversacional',
}: {
  agentBusyAction?: AgentAction | null;
  agentLoading?: boolean;
  agentStates?: ConversationAgentState[];
  contact: ChatContact;
  onAgentAction: (contact: ChatContact, action: AgentAction, stateHint?: ConversationAgentState | null) => void;
  sectionLabel?: string;
}) {
  const contactAgentStates = getControllableConversationAgentStates(agentStates);
  const hasAgentControls = hasConversationAgentControls(agentStates, agentLoading);
  const agentActionBusy = Boolean(agentBusyAction);
  const getAgentActionTitle = (base: string, state: ConversationAgentState) => (
    contactAgentStates.length > 1 ? `${base} ${getAgentDisplayName(state)}` : `${base} agente`
  );

  if (!hasAgentControls) return null;

  return (
    <>
      <View style={styles.sheetSectionDivider}>
        <Text style={styles.sheetSectionLabel}>{sectionLabel}</Text>
        {agentLoading ? <ActivityIndicator color={COLORS.accent} /> : null}
      </View>
      {contactAgentStates.map((state, index) => {
        const stateKey = state.agentId || state.id || `agent-${index}`;
        const inactiveAgent = isInactiveAgentStatus(state.status);
        const continueAction = getResumeAgentAction(state);
        return (
          <React.Fragment key={stateKey}>
            {hasPendingAgentSignal(state) ? (
              <SheetActionRow
                Icon={CheckCircle2}
                title="Marcar aviso como visto"
                subtitle={state.signalSummary || state.signalReason || 'Limpia la alerta del agente en este chat.'}
                busy={agentBusyAction === 'clear_signal'}
                disabled={agentLoading || agentActionBusy}
                onPress={() => onAgentAction(contact, 'clear_signal', state)}
              />
            ) : null}
            {inactiveAgent ? (
              <SheetActionRow
                Icon={Play}
                title={getAgentActionTitle(isPausedAgentStatus(state.status) ? 'Continuar' : 'Reactivar', state)}
                subtitle={isPausedAgentStatus(state.status) ? 'El agente vuelve a atender este chat.' : 'Vuelve a asignar este chat al agente.'}
                busy={agentBusyAction === continueAction}
                disabled={agentLoading || agentActionBusy}
                onPress={() => onAgentAction(contact, continueAction, state)}
              />
            ) : (
              <>
                <SheetActionRow
                  Icon={Pause}
                  title={getAgentActionTitle('Pausar', state)}
                  subtitle="Detiene el agente durante 24 horas."
                  busy={agentBusyAction === 'pause'}
                  disabled={agentLoading || agentActionBusy}
                  onPress={() => onAgentAction(contact, 'pause', state)}
                />
                <SheetActionRow
                  Icon={User}
                  title={getAgentActionTitle('Tomar', state)}
                  subtitle="Detiene al agente y deja esta conversación en humano."
                  busy={agentBusyAction === 'take_over'}
                  disabled={agentLoading || agentActionBusy}
                  onPress={() => onAgentAction(contact, 'take_over', state)}
                />
                <SheetActionRow
                  Icon={X}
                  title={getAgentActionTitle('Omitir', state)}
                  subtitle="El agente no vuelve a tomar este chat hasta reactivarlo."
                  danger
                  busy={agentBusyAction === 'skip'}
                  disabled={agentLoading || agentActionBusy}
                  onPress={() => onAgentAction(contact, 'skip', state)}
                />
              </>
            )}
          </React.Fragment>
        );
      })}
    </>
  );
}

function NativeConversationAgentSheet({
  agentBusyAction,
  agentLoading,
  agentStates = [],
  closing,
  contact,
  open,
  onAgentAction,
  onClose,
}: {
  agentBusyAction?: AgentAction | null;
  agentLoading?: boolean;
  agentStates?: ConversationAgentState[];
  closing?: boolean;
  contact: ChatContact;
  open: boolean;
  onAgentAction: (contact: ChatContact, action: AgentAction, stateHint?: ConversationAgentState | null) => void;
  onClose: () => void;
}) {
  const primaryState = selectPrimaryAgentState(agentStates);
  const signalState = getPendingConversationAgentSignalState(agentStates);
  const displayedState = signalState || primaryState;
  const hasSignal = Boolean(signalState);
  const hasAssignedRows = hasConversationAgentControls(agentStates, agentLoading);
  const hasContent = hasAssignedRows || hasSignal;
  return (
    <BottomActionSheet
      closing={closing}
      open={open}
      title="Agente conversacional"
      subtitle={getContactName(contact)}
      onClose={onClose}
    >
      <View style={styles.agentControlSummary}>
        <View style={[styles.agentControlSummaryIcon, hasSignal && styles.agentControlSummaryIconAlert]}>
          {hasSignal ? (
            <CircleAlert size={19} color={COLORS.white} strokeWidth={2.6} />
          ) : (
            <ConversationAgentAssignmentIcon paused={isPausedAgentStatus(displayedState?.status)} size={19} />
          )}
        </View>
        <View style={styles.agentControlSummaryCopy}>
          <Text style={styles.agentControlSummaryTitle}>{getAgentStatusTitle(displayedState)}</Text>
          <Text style={styles.agentControlSummaryText}>{getAgentStatusDescription(displayedState)}</Text>
        </View>
      </View>
      <ScrollView contentContainerStyle={styles.sheetActionList} showsVerticalScrollIndicator={false}>
        {signalState && !isAssignedConversationAgentState(signalState) ? (
          <SheetActionRow
            Icon={CheckCircle2}
            title="Marcar aviso como visto"
            subtitle={signalState.signalSummary || signalState.signalReason || 'Limpia la alerta del agente en este chat.'}
            busy={agentBusyAction === 'clear_signal'}
            disabled={agentLoading || Boolean(agentBusyAction)}
            onPress={() => onAgentAction(contact, 'clear_signal', signalState)}
          />
        ) : null}
        <ConversationAgentActionRows
          agentBusyAction={agentBusyAction}
          agentLoading={agentLoading}
          agentStates={agentStates}
          contact={contact}
          onAgentAction={onAgentAction}
          sectionLabel="Controles"
        />
        {!hasContent && !agentLoading ? (
          <Text style={styles.agentControlEmpty}>Este chat todavía no tiene agente asignado.</Text>
        ) : null}
      </ScrollView>
    </BottomActionSheet>
  );
}

function ChatMoreSheet({
  archived,
  agentBusyAction,
  agentLoading,
  agentStates = [],
  agentState,
  closing,
  contact,
  muted,
  open,
  unread,
  onAgentAction,
  onAppointment,
  onArchiveToggle,
  onClose,
  onMarkRead,
  onPayment,
  onSchedule,
  onSelect,
  onTag,
  onToggleMute,
}: {
  archived: boolean;
  agentBusyAction?: AgentAction | null;
  agentLoading?: boolean;
  agentStates?: ConversationAgentState[];
  agentState?: ConversationAgentState | null;
  closing?: boolean;
  contact: ChatContact | null;
  muted: boolean;
  open: boolean;
  unread: number;
  onAgentAction: (contact: ChatContact, action: AgentAction, stateHint?: ConversationAgentState | null) => void;
  onAppointment: (contact: ChatContact) => void;
  onArchiveToggle: (contact: ChatContact) => void;
  onClose: () => void;
  onMarkRead: (contact: ChatContact) => void;
  onPayment: (contact: ChatContact) => void;
  onSchedule: (contact: ChatContact) => void;
  onSelect: (contact: ChatContact) => void;
  onTag: (contact: ChatContact) => void;
  onToggleMute: (contact: ChatContact) => void;
}) {
  const resolvedAgentStates = agentStates.length ? agentStates : agentState ? [agentState] : [];
  const hasAgentControls = hasConversationAgentControls(resolvedAgentStates, agentLoading);
  return (
    <BottomActionSheet
      closing={closing}
      open={open && Boolean(contact)}
      title="Más acciones"
      subtitle={contact ? getContactName(contact) : ''}
      onClose={onClose}
    >
      {contact ? (
        <ScrollView contentContainerStyle={styles.sheetActionList} showsVerticalScrollIndicator={false}>
          {hasAgentControls ? (
            <>
              <ConversationAgentActionRows
                agentBusyAction={agentBusyAction}
                agentLoading={agentLoading}
                agentStates={resolvedAgentStates}
                contact={contact}
                onAgentAction={onAgentAction}
              />
            </>
          ) : null}
          <View style={styles.sheetSectionDivider}>
            <Text style={styles.sheetSectionLabel}>Chat</Text>
          </View>
          <SheetActionRow
            Icon={ListChecks}
            title="Seleccionar"
            subtitle="Activa selección múltiple desde esta conversación."
            onPress={() => onSelect(contact)}
          />
          <SheetActionRow
            Icon={CalendarDays}
            title="Agendar cita"
            subtitle="Crear una cita para este contacto."
            onPress={() => onAppointment(contact)}
          />
          <SheetActionRow
            Icon={CircleDollarSign}
            title="Registrar pagos"
            subtitle="Registrar un cobro para este contacto."
            onPress={() => onPayment(contact)}
          />
          <SheetActionRow
            Icon={Clock}
            title="Programar mensaje"
            subtitle="Elige fecha y hora exacta de envío."
            onPress={() => onSchedule(contact)}
          />
          <SheetActionRow
            Icon={Tag}
            title="Agregar etiqueta"
            subtitle="Clasificar este chat con una etiqueta."
            onPress={() => onTag(contact)}
          />
          <SheetActionRow
            Icon={muted ? Bell : BellOff}
            title={muted ? 'Quitar silencio' : 'Silenciar'}
            subtitle={muted ? 'Quita la marca de silencio de este chat.' : 'Marca este chat como silenciado.'}
            onPress={() => onToggleMute(contact)}
          />
          <View style={styles.sheetSectionDivider}>
            <Text style={styles.sheetSectionLabel}>Bandeja</Text>
          </View>
          {unread > 0 ? (
            <SheetActionRow
              Icon={CheckCheck}
              title="Marcar como leído"
              subtitle="Quita los pendientes de esta conversación."
              onPress={() => onMarkRead(contact)}
            />
          ) : null}
          <SheetActionRow
            Icon={Archive}
            title={archived ? 'Restaurar chat' : 'Archivar chat'}
            subtitle={archived ? 'Devuelve la conversación a la bandeja principal.' : 'Mueve la conversación a Archivados.'}
            onPress={() => onArchiveToggle(contact)}
          />
        </ScrollView>
      ) : null}
    </BottomActionSheet>
  );
}

function ContactTagSheet({
  busy,
  closing,
  contact,
  loading,
  open,
  query,
  tags,
  onApply,
  onChangeQuery,
  onClose,
  onCreate,
}: {
  busy: boolean;
  closing?: boolean;
  contact: ChatContact | null;
  loading: boolean;
  open: boolean;
  query: string;
  tags: ContactTag[];
  onApply: (contact: ChatContact, tag: ContactTag) => void;
  onChangeQuery: (value: string) => void;
  onClose: () => void;
  onCreate: (contact: ChatContact) => void;
}) {
  const normalized = query.trim().toLowerCase();
  const filteredTags = tags.filter((tag) => (
    !normalized || tag.name.toLowerCase().includes(normalized)
  ));
  const exactTagExists = Boolean(normalized && tags.some((tag) => tag.name.toLowerCase() === normalized));

  return (
    <BottomActionSheet
      closing={closing}
      open={open && Boolean(contact)}
      title="Agregar etiqueta"
      subtitle={contact ? getContactName(contact) : ''}
      onClose={onClose}
    >
      {contact ? (
        <View style={styles.contactPickerBody}>
          <View style={[styles.sheetSearchBox, styles.contactPickerSearchBox]}>
            <Search size={19} color={COLORS.muted} strokeWidth={2.4} />
            <TextInput
              value={query}
              onChangeText={onChangeQuery}
              placeholder="Buscar o crear etiqueta"
              placeholderTextColor={COLORS.muted}
              autoCapitalize="sentences"
              autoCorrect={false}
              style={styles.sheetSearchInput}
            />
          </View>
          {loading ? (
            <View style={styles.sheetInlineState}>
              <ActivityIndicator color={COLORS.accent} />
              <Text style={styles.caption}>Cargando etiquetas...</Text>
            </View>
          ) : (
            <ScrollView contentContainerStyle={styles.sheetActionList} keyboardShouldPersistTaps="handled" showsVerticalScrollIndicator={false}>
              {filteredTags.map((tag) => (
                <SheetActionRow
                  key={tag.id}
                  Icon={Tag}
                  title={tag.name}
                  subtitle={(contact.tags || []).includes(tag.id) ? 'Ya está agregada.' : 'Agregar a este chat.'}
                  disabled={(contact.tags || []).includes(tag.id)}
                  busy={busy}
                  onPress={() => onApply(contact, tag)}
                />
              ))}
              {normalized && !exactTagExists ? (
                <SheetActionRow
                  Icon={Plus}
                  title={`Crear "${query.trim()}"`}
                  subtitle="Crea la etiqueta y la agrega a este contacto."
                  busy={busy}
                  onPress={() => onCreate(contact)}
                />
              ) : null}
              {!filteredTags.length && !normalized ? (
                <Text style={styles.contactPickerEmpty}>No hay etiquetas para mostrar.</Text>
              ) : null}
            </ScrollView>
          )}
        </View>
      ) : null}
    </BottomActionSheet>
  );
}

function ScheduleMessageSheet({
  busy,
  closing,
  contact,
  draft,
  editing = false,
  error,
  open,
  text,
  timezone,
  onChangeDraft,
  onChangeText,
  onClose,
  onSubmit,
}: {
  busy: boolean;
  closing?: boolean;
  contact: ChatContact | null;
  draft: ScheduleDraft;
  editing?: boolean;
  error?: string;
  open: boolean;
  text: string;
  timezone: string;
  onChangeDraft: (patch: Partial<ScheduleDraft>) => void;
  onChangeText: (value: string) => void;
  onClose: () => void;
  onSubmit: (contact: ChatContact) => void;
}) {
  const [datePickerOpen, setDatePickerOpen] = useState(false);
  const [datePickerMonth, setDatePickerMonth] = useState(() => draft.date || todayDateOnlyInBusinessTimezone(timezone));
  const previewDate = getScheduleDateFromDraft(draft, timezone);
  const canSubmit = Boolean(text.trim() && previewDate && !busy);

  useEffect(() => {
    if (draft.date) setDatePickerMonth(draft.date);
  }, [draft.date]);

  useEffect(() => {
    if (!open) setDatePickerOpen(false);
  }, [open]);

  return (
    <BottomActionSheet
      closing={closing}
      floatingOverlay={(
        <ScheduleDatePickerPanel
          monthDateOnly={datePickerMonth}
          open={datePickerOpen}
          selectedDateOnly={draft.date}
          timezone={timezone}
          onChangeMonth={setDatePickerMonth}
          onClose={() => setDatePickerOpen(false)}
          onReset={() => {
            const today = todayDateOnlyInBusinessTimezone(timezone);
            setDatePickerMonth(today);
            onChangeDraft({ date: today });
          }}
          onSelect={(dateOnly) => {
            onChangeDraft({ date: dateOnly });
            setDatePickerMonth(dateOnly);
            setDatePickerOpen(false);
          }}
        />
      )}
      open={open && Boolean(contact)}
      title={editing ? 'Editar programación' : 'Programar mensaje'}
      subtitle={contact ? getContactName(contact) : ''}
      onClose={onClose}
    >
      {contact ? (
        <>
          <ScrollView contentContainerStyle={styles.scheduleSheetBody} keyboardShouldPersistTaps="handled" showsVerticalScrollIndicator={false}>
            <TextInput
              value={text}
              onChangeText={onChangeText}
              placeholder="Escribe el mensaje"
              placeholderTextColor={COLORS.muted}
              multiline
              keyboardAppearance={getNativeKeyboardAppearance()}
              textAlignVertical="top"
              style={styles.scheduleTextInput}
            />

            <View style={styles.scheduleFields}>
              <View style={styles.scheduleField}>
                <Text style={styles.scheduleFieldLabel}>Fecha</Text>
                <Pressable
                  accessibilityRole="button"
                  onPress={() => {
                    setDatePickerMonth(draft.date || todayDateOnlyInBusinessTimezone(timezone));
                    setDatePickerOpen(true);
                  }}
                  style={({ pressed }) => [styles.scheduleFieldButton, pressed && styles.pressed]}
                >
                  <LiquidControlBackground />
                  <Text numberOfLines={1} style={styles.scheduleFieldButtonText}>{formatCompactBusinessDate(draft.date)}</Text>
                  <ChevronDown size={18} color={COLORS.meta} strokeWidth={2.45} />
                </Pressable>
                <Text numberOfLines={1} style={styles.scheduleFieldHint}>{formatScheduleDateDisplay(draft.date)}</Text>
              </View>

              <View style={styles.scheduleTimeRow}>
                <View style={[styles.scheduleField, styles.scheduleTimeField]}>
                  <Text style={styles.scheduleFieldLabel}>Hora</Text>
                  <TextInput
                    value={draft.hour}
                    onChangeText={(value) => onChangeDraft({ hour: cleanScheduleNumber(value) })}
                    onEndEditing={() => {
                      const hour = Math.min(12, Math.max(1, Number(draft.hour) || 1));
                      onChangeDraft({ hour: String(hour) });
                    }}
                    placeholder="9"
                    placeholderTextColor={COLORS.muted}
                    autoCapitalize="none"
                    autoCorrect={false}
                    keyboardAppearance={getNativeKeyboardAppearance()}
                    keyboardType="number-pad"
                    style={[styles.scheduleFieldInput, styles.scheduleNumericInput]}
                  />
                </View>

                <View style={[styles.scheduleField, styles.scheduleTimeField]}>
                  <Text style={styles.scheduleFieldLabel}>Min</Text>
                  <TextInput
                    value={draft.minute}
                    onChangeText={(value) => onChangeDraft({ minute: cleanScheduleNumber(value) })}
                    onEndEditing={() => {
                      const minute = Math.min(59, Math.max(0, Number(draft.minute) || 0));
                      onChangeDraft({ minute: padSchedulePart(minute) });
                    }}
                    placeholder="00"
                    placeholderTextColor={COLORS.muted}
                    autoCapitalize="none"
                    autoCorrect={false}
                    keyboardAppearance={getNativeKeyboardAppearance()}
                    keyboardType="number-pad"
                    style={[styles.scheduleFieldInput, styles.scheduleNumericInput]}
                  />
                </View>

                <View style={styles.schedulePeriodToggle}>
                  {(['AM', 'PM'] as SchedulePeriod[]).map((period) => {
                    const active = draft.period === period;
                    return (
                      <Pressable
                        key={period}
                        accessibilityRole="button"
                        onPress={() => onChangeDraft({ period })}
                        style={({ pressed }) => [
                          styles.schedulePeriodButton,
                          active && styles.schedulePeriodButtonActive,
                          pressed && styles.pressed,
                        ]}
                      >
                        <LiquidControlBackground selected={active} />
                        <Text style={[styles.schedulePeriodText, active && styles.schedulePeriodTextActive]}>{period}</Text>
                      </Pressable>
                    );
                  })}
                </View>
              </View>
            </View>

            <View style={styles.schedulePreview}>
              <Clock size={16} color={COLORS.accent} strokeWidth={2.4} />
              <Text style={styles.schedulePreviewText}>{formatSchedulePreviewLabel(previewDate?.toISOString(), timezone)}</Text>
            </View>

            {error ? <Text style={styles.scheduleErrorText}>{error}</Text> : null}

            <PrimaryButton
              label={editing ? 'Actualizar programación' : 'Enviar programación'}
              busy={busy}
              disabled={!canSubmit}
              onPress={() => onSubmit(contact)}
            />
          </ScrollView>
        </>
      ) : null}
    </BottomActionSheet>
  );
}

function ScheduleDatePickerPanel({
  monthDateOnly,
  onChangeMonth,
  onClose,
  onReset,
  onSelect,
  open,
  selectedDateOnly,
  timezone,
}: {
  monthDateOnly: string;
  onChangeMonth: (value: string) => void;
  onClose: () => void;
  onReset: () => void;
  onSelect: (dateOnly: string) => void;
  open: boolean;
  selectedDateOnly: string;
  timezone: string;
}) {
  const today = todayDateOnlyInBusinessTimezone(timezone);
  const cells = useMemo(() => buildBusinessMonthCells(monthDateOnly, today), [monthDateOnly, today]);
  if (!open) return null;

  return (
    <View style={styles.schedulePickerLayer}>
      <Pressable style={styles.schedulePickerBackdrop} onPress={onClose} />
      <View style={styles.schedulePickerCard}>
        <View pointerEvents="none" style={styles.schedulePickerSurface} />
        <View style={styles.actionSheetHandle} />
        <View style={styles.schedulePickerHeader}>
          <Pressable accessibilityRole="button" accessibilityLabel="Mes anterior" onPress={() => onChangeMonth(addBusinessDateOnlyMonths(monthDateOnly, -1))} style={styles.schedulePickerIconButton}>
            <LiquidControlBackground />
            <ChevronLeft size={24} color={COLORS.text} strokeWidth={2.6} />
          </Pressable>
          <Text style={styles.schedulePickerTitle}>{formatSchedulePickerMonthLabel(monthDateOnly)}</Text>
          <Pressable accessibilityRole="button" accessibilityLabel="Mes siguiente" onPress={() => onChangeMonth(addBusinessDateOnlyMonths(monthDateOnly, 1))} style={styles.schedulePickerIconButton}>
            <LiquidControlBackground />
            <ChevronRight size={24} color={COLORS.text} strokeWidth={2.6} />
          </Pressable>
        </View>
        <View style={styles.schedulePickerWeekRow}>
          {SCHEDULE_PICKER_WEEKDAYS.map((day) => <Text key={day} style={styles.schedulePickerWeekday}>{day}</Text>)}
        </View>
        <View style={styles.schedulePickerGrid}>
          {cells.map((cell) => {
            const selected = cell.dateOnly === selectedDateOnly;
            const disabled = cell.dateOnly < today;
            return (
              <Pressable
                key={cell.dateOnly}
                accessibilityRole="button"
                accessibilityLabel={`Elegir ${formatScheduleDateDisplay(cell.dateOnly)}`}
                disabled={disabled}
                onPress={() => onSelect(cell.dateOnly)}
                style={({ pressed }) => [
                  styles.schedulePickerDay,
                  selected && styles.schedulePickerDaySelected,
                  disabled && styles.schedulePickerDayDisabled,
                  pressed && styles.pressed,
                ]}
              >
                <Text style={[
                  styles.schedulePickerDayText,
                  !cell.isCurrentMonth && styles.schedulePickerDayTextMuted,
                  disabled && styles.schedulePickerDayTextDisabled,
                  selected && styles.schedulePickerDayTextSelected,
                ]}
                >
                  {cell.day}
                </Text>
              </Pressable>
            );
          })}
        </View>
        <View style={styles.schedulePickerFooter}>
          <Pressable accessibilityRole="button" onPress={onReset} style={({ pressed }) => [styles.schedulePickerReset, pressed && styles.pressed]}>
            <LiquidControlBackground />
            <Text style={styles.schedulePickerResetText}>Restablecer</Text>
          </Pressable>
          <Pressable accessibilityRole="button" onPress={onClose} style={({ pressed }) => [styles.schedulePickerDone, pressed && styles.pressed]}>
            <Check size={30} color={COLORS.white} strokeWidth={2.7} />
          </Pressable>
        </View>
      </View>
    </View>
  );
}

function NativeTemplatesSheet({
  busyId,
  closing,
  contact,
  loading,
  open,
  templates,
  onClose,
  onSend,
}: {
  busyId?: string | null;
  closing?: boolean;
  contact: ChatContact | null;
  loading: boolean;
  open: boolean;
  templates: WhatsAppTemplate[];
  onClose: () => void;
  onSend: (template: WhatsAppTemplate) => void;
}) {
  return (
    <BottomActionSheet
      closing={closing}
      open={open && Boolean(contact)}
      title="Plantillas"
      subtitle={contact ? getContactName(contact) : ''}
      onClose={onClose}
    >
      {contact ? (
        <View style={styles.templatesSheetBody}>
          {loading ? (
            <View style={styles.sheetInlineState}>
              <ActivityIndicator color={COLORS.accent} />
              <Text style={styles.caption}>Cargando plantillas...</Text>
            </View>
          ) : (
            <ScrollView contentContainerStyle={styles.sheetActionList} keyboardShouldPersistTaps="handled" showsVerticalScrollIndicator={false}>
              {templates.map((template, index) => {
                const body = getTemplateBody(template);
                const key = template.id || template.name || body || `template-${index}`;
                const templateStatus = template.source === 'whatsapp' ? String(template.status || '').toUpperCase() : '';
                const templateBlocked = Boolean(templateStatus) && templateStatus !== 'APPROVED';
                const subtitle = templateBlocked
                  ? `WhatsApp · ${getTemplateStatusLabel(templateStatus) || templateStatus.toLowerCase()}`
                  : (body || template.category || (template.source === 'local' ? 'Inserta una respuesta guardada.' : 'Enviar plantilla aprobada por WhatsApp.'));
                return (
                  <SheetActionRow
                    key={key}
                    Icon={MessageCircle}
                    title={template.name || 'Plantilla'}
                    subtitle={subtitle}
                    busy={busyId === key}
                    onPress={() => onSend(template)}
                  />
                );
              })}
              {!templates.length ? (
                <Text style={styles.contactPickerEmpty}>No hay plantillas aprobadas o guardadas para mostrar.</Text>
              ) : null}
            </ScrollView>
          )}
        </View>
      ) : null}
    </BottomActionSheet>
  );
}

function NativeClabeSheet({
  accounts,
  busyId,
  closing,
  contact,
  draft,
  formOpen,
  loading,
  open,
  onChangeDraft,
  onClose,
  onSave,
  onSend,
  onToggleForm,
}: {
  accounts: BankClabeAccount[];
  busyId?: string | null;
  closing?: boolean;
  contact: ChatContact | null;
  draft: { alias: string; clabe: string; bank: string; accountHolder: string };
  formOpen: boolean;
  loading: boolean;
  open: boolean;
  onChangeDraft: React.Dispatch<React.SetStateAction<{ alias: string; clabe: string; bank: string; accountHolder: string }>>;
  onClose: () => void;
  onSave: () => void;
  onSend: (account: BankClabeAccount) => void;
  onToggleForm: () => void;
}) {
  return (
    <BottomActionSheet
      closing={closing}
      open={open && Boolean(contact)}
      title="Enviar CLABE"
      subtitle={contact ? getContactName(contact) : ''}
      onClose={onClose}
    >
      {contact ? (
        <View style={styles.clabeSheetBody}>
          <SecondaryButton label={formOpen ? 'Ocultar formulario' : 'Agregar CLABE'} onPress={onToggleForm} />
          {formOpen ? (
            <View style={styles.sheetFormBlock}>
              <TextInput
                value={draft.alias}
                onChangeText={(value) => onChangeDraft((current) => ({ ...current, alias: value }))}
                placeholder="Alias"
                placeholderTextColor={COLORS.muted}
                keyboardAppearance={getNativeKeyboardAppearance()}
                style={styles.sheetInput}
              />
              <TextInput
                value={formatClabe(draft.clabe)}
                onChangeText={(value) => onChangeDraft((current) => ({ ...current, clabe: normalizeClabe(value) }))}
                placeholder="CLABE de 18 dígitos"
                placeholderTextColor={COLORS.muted}
                keyboardAppearance={getNativeKeyboardAppearance()}
                keyboardType="number-pad"
                style={styles.sheetInput}
              />
              <TextInput
                value={draft.bank}
                onChangeText={(value) => onChangeDraft((current) => ({ ...current, bank: value }))}
                placeholder="Banco"
                placeholderTextColor={COLORS.muted}
                keyboardAppearance={getNativeKeyboardAppearance()}
                style={styles.sheetInput}
              />
              <TextInput
                value={draft.accountHolder}
                onChangeText={(value) => onChangeDraft((current) => ({ ...current, accountHolder: value }))}
                placeholder="Titular"
                placeholderTextColor={COLORS.muted}
                keyboardAppearance={getNativeKeyboardAppearance()}
                style={styles.sheetInput}
              />
              <PrimaryButton label="Guardar CLABE" busy={Boolean(busyId)} onPress={onSave} />
            </View>
          ) : null}
          {loading ? (
            <View style={styles.sheetInlineState}>
              <ActivityIndicator color={COLORS.accent} />
              <Text style={styles.caption}>Cargando cuentas...</Text>
            </View>
          ) : (
            <ScrollView contentContainerStyle={styles.sheetActionList} keyboardShouldPersistTaps="handled" showsVerticalScrollIndicator={false}>
              {accounts.map((account) => (
                <SheetActionRow
                  key={account.id}
                  Icon={Banknote}
                  title={account.alias || `CLABE ${account.clabe.slice(-4)}`}
                  subtitle={[account.bank, account.accountHolder, formatClabe(account.clabe)].filter(Boolean).join(' · ')}
                  busy={busyId === account.id}
                  onPress={() => onSend(account)}
                />
              ))}
              {!accounts.length ? (
                <Text style={styles.contactPickerEmpty}>No hay CLABEs guardadas. Agrega una para enviarla desde el chat.</Text>
              ) : null}
            </ScrollView>
          )}
        </View>
      ) : null}
    </BottomActionSheet>
  );
}

