function isOutboundMessageDirection(value?: string | null) {
  return [
    'outbound',
    'outgoing',
    'sent',
    'business',
    'api',
    'app',
    'business_echo',
    'smb_echo',
    'echo',
    'message_echo',
  ].includes(normalizeProbe(value));
}

function getUnreadCount(contact: ChatContact) {
  if (isOutboundMessageDirection(contact.lastMessageDirection)) return 0;
  return Math.max(0, Number(contact.unreadCount || 0));
}

function normalizeProbe(value?: string | null) {
  return String(value || '').trim().toLowerCase().replace(/[\s-]+/g, '_');
}

function getChannelProbe(contact: ChatContact) {
  return [
    contact.lastMessageChannel,
    contact.lastMessageTransport,
    contact.whatsappAttributionPlatform,
    contact.attribution_session_source,
    contact.source,
  ].map((value) => normalizeProbe(value)).filter(Boolean).join(' ');
}

function contactHasCommentActivity(contact: ChatContact) {
  if (contact.hasCommentMessage !== undefined) return Boolean(contact.hasCommentMessage);
  return normalizeProbe(contact.lastMessageType).startsWith('comment');
}

function getContactChannelKind(contact: ChatContact): ChannelBadgeKind {
  const probe = getChannelProbe(contact);
  if (contactHasCommentActivity(contact) && contact.hasPrivateDm !== true) {
    return probe.includes('instagram') ? 'instagram_comment' : 'facebook_comment';
  }
  if (probe.includes('instagram') || probe.includes('ig_') || probe === 'ig') return 'instagram';
  if (probe.includes('messenger') || probe.includes('fb_messenger')) return 'messenger';
  if (probe.includes('email') || probe.includes('mail') || probe.includes('correo')) return 'email';
  if (probe.includes('sms')) return 'sms';
  if (probe.includes('whatsapp') || probe.includes('api') || probe.includes('qr')) return 'whatsapp';
  return 'unknown';
}

function getDefaultComposerChannel(contact: ChatContact): NativeMessageChannel {
  const kind = getContactChannelKind(contact);
  if (kind === 'instagram' || kind === 'instagram_comment') return 'instagram';
  if (kind === 'messenger' || kind === 'facebook_comment') return 'messenger';
  if (kind === 'sms') return 'sms';
  if (kind === 'email') return 'email';
  return 'whatsapp';
}

function isCommentComposerRoute(value?: ComposerChannelRouteValue | ComposerRouteChannel | null): value is CommentComposerChannel {
  return value === 'facebook_comment' || value === 'instagram_comment';
}

function getCommentComposerPlatform(value: CommentComposerChannel): 'messenger' | 'instagram' {
  return value === 'instagram_comment' ? 'instagram' : 'messenger';
}

function getCommentComposerChannelForPlatform(platform: 'messenger' | 'instagram'): CommentComposerChannel {
  return platform === 'instagram' ? 'instagram_comment' : 'facebook_comment';
}

function getCommentComposerLabel(platform: 'messenger' | 'instagram') {
  return platform === 'instagram' ? 'Comentario de Instagram' : 'Comentario de Facebook';
}

function getBackendChannelForComposer(channel: ComposerRouteChannel) {
  if (channel === 'facebook_comment') return 'messenger';
  if (channel === 'instagram_comment') return 'instagram';
  if (channel === 'sms') return 'sms_qr';
  if (channel === 'email') return 'email';
  if (channel === 'messenger') return 'messenger';
  if (channel === 'instagram') return 'instagram';
  return 'whatsapp_api';
}

function getScheduleChannelUnavailableReason(channel: NativeMessageChannel, contact?: ChatContact) {
  if (channel === 'messenger' || channel === 'instagram') {
    return 'La programación para Messenger e Instagram todavía no está disponible. Puedes enviarlo al momento desde Ristak.';
  }
  if (channel === 'email') {
    return 'La programación por correo todavía no está disponible desde la app móvil.';
  }
  if ((channel === 'whatsapp' || channel === 'sms') && contact && !contact.phone) {
    return 'Este contacto necesita teléfono para programar por WhatsApp o SMS.';
  }
  return '';
}

function contactProbeIncludes(contact: ChatContact, value: string) {
  return getChannelProbe(contact).includes(value);
}

function isWhatsAppComposerRoute(value: ComposerChannelRouteValue): value is `whatsapp:${string}` {
  return String(value).startsWith('whatsapp:');
}

function getComposerRoutePhoneId(value: ComposerChannelRouteValue) {
  return isWhatsAppComposerRoute(value) ? String(value).slice('whatsapp:'.length) : '';
}

function getComposerRouteChannel(value: ComposerChannelRouteValue): ComposerRouteChannel {
  if (isWhatsAppComposerRoute(value)) return 'whatsapp';
  if (String(value).startsWith('highlevel:whatsapp')) return 'whatsapp';
  if (String(value).startsWith('highlevel:sms')) return 'sms';
  return value as ComposerRouteChannel;
}

function getPreferredComposerPhoneId(contact: ChatContact) {
  return getPreferredWhatsAppPhoneId(contact);
}

function canStartNativeCommentPublicReply(message: ChatMessage) {
  return Boolean(
    message.isComment &&
    message.direction === 'inbound' &&
    !message.commentReplyMode &&
    message.commentId
  );
}

function buildNativeCommentReplyTarget(message: ChatMessage): NativeCommentReplyTarget | null {
  if (!canStartNativeCommentPublicReply(message) || !message.commentId) return null;
  return {
    messageId: message.id,
    commentId: message.commentId,
    platform: message.commentPlatform || 'messenger',
    preview: getMessagePreviewText(message).replace(/\s+/g, ' ').trim().slice(0, 60),
  };
}

function getLatestEligibleNativeCommentReplyTarget(messages: ChatMessage[]): NativeCommentReplyTarget | null {
  const latestComment = [...messages]
    .filter(canStartNativeCommentPublicReply)
    .sort((left, right) => parseSortableDateValue(right.date) - parseSortableDateValue(left.date))[0];
  if (!latestComment) return null;

  const latestCommentTime = parseSortableDateValue(latestComment.date);
  const hasLaterInboundPrivateMessage = messages.some((message) => (
    message.direction === 'inbound' &&
    !message.isComment &&
    parseSortableDateValue(message.date) > latestCommentTime
  ));
  if (hasLaterInboundPrivateMessage) return null;

  return buildNativeCommentReplyTarget(latestComment);
}

function isBusinessPhoneQrReady(phone?: WhatsAppApiPhoneNumber | null) {
  return Boolean(phone?.qr_send_enabled && String(phone.qr_status || '').toLowerCase() === 'connected');
}

function isBusinessPhoneSendReady(phone?: WhatsAppApiPhoneNumber | null) {
  if (!phone?.id) return false;
  if (phone.availability) {
    return Boolean(
      phone.availability.available
      || phone.availability.apiAvailable
      || phone.availability.qrReady
      || isBusinessPhoneQrReady(phone)
    );
  }
  return phone.api_send_enabled !== false || isBusinessPhoneQrReady(phone);
}

function isHighLevelConnected(integrations?: IntegrationsStatus | null) {
  return Boolean(integrations?.highlevel?.connected);
}

function isNativeMessengerConnected(integrations?: IntegrationsStatus | null) {
  return Boolean(integrations?.meta?.connected && integrations.meta.pageId);
}

function isNativeInstagramConnected(integrations?: IntegrationsStatus | null) {
  return Boolean(integrations?.meta?.connected && integrations.meta.instagramAccountId);
}

function getDefaultComposerRoute(contact: ChatContact, options: ComposerChannelOption[]): ComposerChannelRouteValue {
  if (contactHasCommentActivity(contact) && contact.hasPrivateDm !== true) {
    const commentOption = options.find((option) => isCommentComposerRoute(option.channel) && !option.disabledReason);
    if (commentOption) return commentOption.value;
  }
  const preferredChannel = getDefaultComposerChannel(contact);
  const lastTransport = String(contact.lastMessageTransport || '').trim().toLowerCase();
  if (lastTransport.startsWith('ghl_') || lastTransport.includes('highlevel')) {
    const highLevelOption = options.find((option) => (
      option.provider === 'highlevel'
      && option.channel === preferredChannel
      && !option.disabledReason
    ));
    if (highLevelOption) return highLevelOption.value;
  }
  const preferredPhoneId = getPreferredComposerPhoneId(contact);
  if (preferredChannel === 'whatsapp' && preferredPhoneId) {
    const preferredPhoneOption = options.find((option) => option.channel === 'whatsapp' && option.phoneNumberId === preferredPhoneId && !option.disabledReason);
    if (preferredPhoneOption) return preferredPhoneOption.value;
  }
  const preferredOption = options.find((option) => option.channel === preferredChannel && !option.disabledReason);
  if (preferredOption) return preferredOption.value;
  const firstEnabled = options.find((option) => !option.disabledReason);
  return firstEnabled?.value || preferredChannel;
}

function getComposerChannelOptions(
  contact: ChatContact,
  businessPhones: WhatsAppApiPhoneNumber[] = [],
  highLevelPhoneNumbers: HighLevelPhoneNumber[] = [],
  integrations?: IntegrationsStatus | null,
  latestCommentReplyTarget?: NativeCommentReplyTarget | null,
  highLevelWhatsAppFromNumber = '',
): ComposerChannelOption[] {
  const kind = getContactChannelKind(contact);
  const hasPhone = Boolean(String(contact.phone || '').trim());
  const isMessengerContact = kind === 'messenger' || kind === 'facebook_comment' || contactProbeIncludes(contact, 'messenger');
  const isInstagramContact = kind === 'instagram' || kind === 'instagram_comment' || contactProbeIncludes(contact, 'instagram');
  const highLevelConnected = isHighLevelConnected(integrations);
  const messengerConnected = isNativeMessengerConnected(integrations);
  const instagramConnected = isNativeInstagramConnected(integrations);
  const connectedPhones = businessPhones.filter((phone) => Boolean(phone.id));
  const whatsappOptions: ComposerChannelOption[] = connectedPhones.map((phone, index) => ({
        value: `whatsapp:${phone.id}` as ComposerChannelRouteValue,
        channel: 'whatsapp',
        phoneNumberId: phone.id,
        label: getNativeWhatsAppRouteLabel(phone) || `WhatsApp · Número ${index + 1}`,
        description: getBusinessPhoneValue(phone) || phone.verified_name || 'Número conectado',
        kind: 'whatsapp',
        provider: 'native' as const,
        disabledReason: !hasPhone
          ? 'Este contacto no tiene teléfono guardado.'
          : isBusinessPhoneSendReady(phone)
            ? undefined
            : phone.availability?.apiReason || phone.qr_last_error || 'Este número de WhatsApp no está disponible para enviar.',
      }));
  const options: ComposerChannelOption[] = [...whatsappOptions];

  if (latestCommentReplyTarget) {
    const commentChannel = getCommentComposerChannelForPlatform(latestCommentReplyTarget.platform);
    const commentConnected = latestCommentReplyTarget.platform === 'instagram' ? instagramConnected : messengerConnected;
    options.unshift({
      value: commentChannel,
      channel: commentChannel,
      label: getCommentComposerLabel(latestCommentReplyTarget.platform),
      description: 'Responde público en la publicación.',
      kind: commentChannel,
      disabledReason: commentConnected ? undefined : 'Conecta Meta Ads para responder comentarios.',
    });
  }

  if (highLevelConnected) {
    options.push({
      value: 'highlevel:whatsapp',
      channel: 'whatsapp',
      label: highLevelWhatsAppFromNumber
        ? `WhatsApp · HighLevel · ${highLevelWhatsAppFromNumber}`
        : 'WhatsApp · HighLevel',
      description: highLevelWhatsAppFromNumber
        ? 'Responde por el número ligado a la sesión activa de HighLevel.'
        : 'HighLevel resolverá el número ligado a la conversación.',
      kind: 'whatsapp',
      provider: 'highlevel',
      highLevelChannel: 'whatsapp_api',
      fromNumber: highLevelWhatsAppFromNumber || undefined,
      disabledReason: hasPhone ? undefined : 'Este contacto no tiene teléfono guardado.',
    });

    const highLevelSmsOptions: ComposerChannelOption[] = highLevelPhoneNumbers.length > 0
      ? highLevelPhoneNumbers.map((phone, index) => ({
          value: `highlevel:sms:${phone.id || index}` as ComposerChannelRouteValue,
          channel: 'sms',
          label: `SMS · ${phone.label || `Número ${index + 1}`}`,
          description: phone.phoneNumber,
          kind: 'sms',
          provider: 'highlevel',
          highLevelChannel: 'sms_qr',
          fromNumber: phone.phoneNumber,
          disabledReason: hasPhone ? undefined : 'Este contacto no tiene teléfono guardado.',
        }))
      : [{
          value: 'highlevel:sms',
          channel: 'sms',
          label: 'SMS · HighLevel',
          description: 'HighLevel elegirá el número configurado en la conversación.',
          kind: 'sms',
          provider: 'highlevel',
          highLevelChannel: 'sms_qr',
          disabledReason: hasPhone ? undefined : 'Este contacto no tiene teléfono guardado.',
        }];
    options.push(...highLevelSmsOptions);
  }

  if (isMessengerContact && messengerConnected) {
    options.push({
      value: 'messenger',
      channel: 'messenger',
      label: 'Messenger',
      description: 'Responde por Facebook Messenger.',
      kind: 'messenger',
    });
  }

  if (isInstagramContact && instagramConnected) {
    options.push({
      value: 'instagram',
      channel: 'instagram',
      label: 'Instagram DM',
      description: 'Responde por Instagram Direct.',
      kind: 'instagram',
    });
  }

  return options;
}

function formatContactMoney(value: number, accountCurrency: string) {
  const amount = Number.isFinite(value) ? value : 0;
  const currency = accountCurrency.trim().toUpperCase();
  if (currency) return formatCurrency(amount, currency);
  return amount.toLocaleString('es-MX', { maximumFractionDigits: 2 });
}

